import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard - A reusable weather display component.
 * Shows current conditions (temperature, humidity, wind) and a 5-day forecast.
 * All data is provided via props with sensible defaults.
 */
export default function WeatherCard(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = '°C',
    forecast = [],
  } = props;

  // Helper function to get emoji for condition if icon not provided
  const getWeatherEmoji = (iconOrCondition?: string): string => {
    if (!iconOrCondition) return '🌤️';
    // If it's already an emoji (single character or multi-byte), return it
    if (iconOrCondition.length <= 2) return iconOrCondition;
    // Otherwise, map common conditions to emojis
    const conditionLower = iconOrCondition.toLowerCase();
    if (
      conditionLower.includes('sunny') ||
      conditionLower.includes('clear')
    )
      return '☀️';
    if (conditionLower.includes('cloudy')) return '☁️';
    if (
      conditionLower.includes('rainy') ||
      conditionLower.includes('rain')
    )
      return '🌧️';
    if (conditionLower.includes('thunder') || conditionLower.includes('storm'))
      return '⛈️';
    if (conditionLower.includes('snow') || conditionLower.includes('snowy'))
      return '❄️';
    if (conditionLower.includes('partly')) return '⛅';
    return '🌤️';
  };

  return (
    <Card
      shadow="md"
      radius="lg"
      padding={24}
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        {/* City heading */}
        <Heading
          level={3}
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {city}
        </Heading>

        {/* Current temperature and condition */}
        <Stack direction="horizontal" gap={12} align="center">
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
            as="span"
          >
            {temperature}
            <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
              {unit}
            </span>
          </Text>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="label"
              size="sm"
              color="var(--ggui-color-onSurface, #18181b)"
              as="span"
            >
              {getWeatherEmoji(condition)}
            </Text>
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="span"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Humidity and Wind Speed */}
        <Stack
          direction="horizontal"
          gap={32}
          justify="start"
          align="start"
        >
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              size="xs"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="span"
            >
              Humidity
            </Text>
            <Text
              variant="label"
              size="base"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
              as="span"
            >
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              size="xs"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="span"
            >
              Wind Speed
            </Text>
            <Text
              variant="label"
              size="base"
              color="var(--ggui-color-onSurface, #18181b)"
              weight="semibold"
              as="span"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin={16}
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        {/* 5-Day Forecast Strip */}
        <Stack
          direction="horizontal"
          gap={8}
          wrap={true}
          align="start"
          justify="start"
        >
          {forecast.length > 0 ? (
            forecast.map((day, index) => (
              <div
                key={day.day || `forecast-${index}`}
                style={{
                  padding: 'var(--ggui-spacing-2, 8px)',
                  backgroundColor:
                    'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  minWidth: '70px',
                  textAlign: 'center',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-1, 4px)',
                }}
              >
                {/* Day name */}
                <Text
                  variant="label"
                  size="xs"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                  weight="medium"
                >
                  {day.day || `Day ${index + 1}`}
                </Text>

                {/* Weather icon/emoji */}
                <div
                  style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    lineHeight: 1,
                  }}
                >
                  {getWeatherEmoji(day.icon)}
                </div>

                {/* High temperature */}
                <Text
                  variant="label"
                  size="sm"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                  as="span"
                >
                  {day.high !== undefined ? `${day.high}°` : '—'}
                </Text>

                {/* Low temperature */}
                <Text
                  variant="bodySmall"
                  size="xs"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  as="span"
                >
                  {day.low !== undefined ? `${day.low}°` : '—'}
                </Text>
              </div>
            ))
          ) : (
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="span"
            >
              No forecast data available
            </Text>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useCallback, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Container,
  Divider,
  Heading,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  tasks?: Task[];
  columns?: Column[];
  onTaskUpdate?: (payload: { action: string; taskId?: string; data?: Task }) => void;
}

const PRIORITY_COLORS: Record<string, 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

const PRIORITY_LABELS: Record<string, string> = {
  low: 'Low',
  medium: 'Medium',
  high: 'High',
};

export default function GeneratedComponent(props: Props) {
  const {
    tasks = [],
    columns = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ],
    onTaskUpdate,
  } = props;

  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addingTaskColumnId, setAddingTaskColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('low');
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string>('');
  const [success, setSuccess] = useState<string>('');

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Task[]> = {};
    columns.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach((task) => {
      const colId = task.column || 'todo';
      if (grouped[colId]) {
        grouped[colId].push(task);
      }
    });
    return grouped;
  }, [localTasks, columns]);

  const completedCount = useMemo(() => {
    return localTasks.filter((t) => t.column === 'done').length;
  }, [localTasks]);

  const handleEditTask = useCallback(
    (taskId: string, currentTitle: string) => {
      setEditingTaskId(taskId);
      setEditingTitle(currentTitle);
    },
    []
  );

  const handleSaveEdit = useCallback(
    (taskId: string) => {
      if (!editingTitle.trim()) {
        setError('Task title cannot be empty');
        return;
      }
      const updatedTasks = localTasks.map((t) =>
        t.id === taskId ? { ...t, title: editingTitle } : t
      );
      setLocalTasks(updatedTasks);
      setEditingTaskId(null);
      setError('');
      onTaskUpdate?.({
        action: 'edit',
        taskId,
        data: { title: editingTitle },
      });
    },
    [editingTitle, localTasks, onTaskUpdate]
  );

  const handleMoveTask = useCallback(
    (taskId: string, newColumnId: string) => {
      const updatedTasks = localTasks.map((t) =>
        t.id === taskId ? { ...t, column: newColumnId } : t
      );
      setLocalTasks(updatedTasks);
      onTaskUpdate?.({
        action: 'move',
        taskId,
        data: { column: newColumnId },
      });
    },
    [localTasks, onTaskUpdate]
  );

  const handleStartAddTask = useCallback((columnId: string) => {
    setAddingTaskColumnId(columnId);
    setNewTaskTitle('');
    setNewTaskPriority('low');
    setError('');
  }, []);

  const handleSubmitNewTask = useCallback(async () => {
    if (!newTaskTitle.trim()) {
      setError('Task title is required');
      return;
    }

    setSubmitting(true);
    try {
      const newTaskId = `task-${Date.now()}`;
      const newTask: Task = {
        id: newTaskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: addingTaskColumnId || 'todo',
        assignee: '',
      };
      setLocalTasks((prev) => [...prev, newTask]);
      onTaskUpdate?.({
        action: 'create',
        taskId: newTaskId,
        data: newTask,
      });
      setAddingTaskColumnId(null);
      setNewTaskTitle('');
      setNewTaskPriority('low');
      setError('');
      setSuccess('Task created successfully');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to create task');
    } finally {
      setSubmitting(false);
    }
  }, [newTaskTitle, newTaskPriority, addingTaskColumnId, onTaskUpdate]);

  const handleCancelAddTask = useCallback(() => {
    setAddingTaskColumnId(null);
    setNewTaskTitle('');
    setNewTaskPriority('low');
    setError('');
  }, []);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">
            KANBAN BOARD
          </Text>
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            Task Board
          </Heading>
        </Stack>

        <Card padding={16} shadow="sm" border={true} radius="lg">
          <Stack direction="horizontal" gap={16} align="center" justify="between">
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                Total Tasks:
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                {localTasks.length}
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={0} />
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                Completed:
              </Text>
              <Badge variant="success" size="md">
                {completedCount} / {localTasks.length}
              </Badge>
            </Stack>
          </Stack>
        </Card>

        <Stack direction="horizontal" gap={16}>
          {columns.map((column) => {
            const columnTasks = tasksByColumn[column.id || ''] || [];
            const isAddingInThisColumn = addingTaskColumnId === column.id;

            return (
              <Card
                key={column.id}
                padding={16}
                shadow="sm"
                border={true}
                radius="lg"
                style={{
                  flex: '1 1 300px',
                  minWidth: '300px',
                  maxHeight: '70vh',
                  overflow: 'auto',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                }}
              >
                <Stack gap={12}>
                  <Stack direction="horizontal" gap={8} align="center" justify="between">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {column.name}
                    </Text>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Stack>

                  <Divider margin={0} />

                  <Stack gap={12}>
                    {columnTasks.map((task) => {
                      const isEditing = editingTaskId === task.id;

                      return (
                        <Card
                          key={task.id}
                          padding={12}
                          shadow="sm"
                          border={true}
                          radius="md"
                          style={{
                            backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                          }}
                        >
                          <Stack gap={8}>
                            {isEditing ? (
                              <Stack gap={6}>
                                <Input
                                  label="Task title"
                                  placeholder="Task title"
                                  size="sm"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                />
                                <Stack direction="horizontal" gap={6} justify="end">
                                  <Button
                                    size="xs"
                                    variant="ghost"
                                    onClick={() => setEditingTaskId(null)}
                                  >
                                    Cancel
                                  </Button>
                                  <Button
                                    size="xs"
                                    variant="primary"
                                    onClick={() => handleSaveEdit(task.id || '')}
                                  >
                                    Save
                                  </Button>
                                </Stack>
                              </Stack>
                            ) : (
                              <div
                                style={{
                                  cursor: 'pointer',
                                  color: 'var(--ggui-color-onSurface, #18181b)',
                                  wordWrap: 'break-word',
                                  fontWeight: 500,
                                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                                  padding: 'var(--ggui-spacing-2, 8px)',
                                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                                }}
                                onClick={() =>
                                  handleEditTask(task.id || '', task.title || '')
                                }
                                role="button"
                                tabIndex={0}
                              >
                                {task.title}
                              </div>
                            )}

                            <Stack direction="horizontal" gap={8} align="center">
                              {task.priority && (
                                <Badge
                                  variant={PRIORITY_COLORS[task.priority] || 'default'}
                                  size="sm"
                                >
                                  {PRIORITY_LABELS[task.priority]}
                                </Badge>
                              )}
                              {task.assignee && (
                                <Avatar
                                  name={task.assignee}
                                  size="xs"
                                  shape="circle"
                                />
                              )}
                            </Stack>

                            {task.dueDate && (
                              <Text
                                variant="caption"
                                color="var(--ggui-color-neutral-500, #6b7280)"
                              >
                                Due: {task.dueDate}
                              </Text>
                            )}

                            <Stack direction="horizontal" gap={6} justify="between">
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={() => handleEditTask(task.id || '', task.title || '')}
                              >
                                Edit
                              </Button>
                              <Select
                                value={task.column || 'todo'}
                                onChange={(newCol) => handleMoveTask(task.id || '', newCol)}
                                options={columns
                                  .filter((c) => c.id !== task.column)
                                  .map((c) => ({
                                    value: c.id || '',
                                    label: `Move to ${c.name}`,
                                  }))}
                                size="sm"
                              />
                            </Stack>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {isAddingInThisColumn ? (
                    <Card
                      padding={12}
                      shadow="sm"
                      border={true}
                      radius="md"
                      style={{
                        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
                      }}
                    >
                      <Stack gap={10}>
                        <Input
                          label="Task title"
                          placeholder="Enter task title"
                          size="sm"
                          error={error}
                          required
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Stack direction="horizontal" gap={8} justify="end">
                          <Button
                            size="xs"
                            variant="ghost"
                            onClick={handleCancelAddTask}
                          >
                            Cancel
                          </Button>
                          <Button
                            size="xs"
                            variant="primary"
                            onClick={handleSubmitNewTask}
                            loading={submitting}
                            disabled={submitting}
                          >
                            Create
                          </Button>
                        </Stack>
                        {success && (
                          <Text
                            variant="caption"
                            color="var(--ggui-color-success-600, #16a34a)"
                          >
                            {success}
                          </Text>
                        )}
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      size="sm"
                      variant="outline"
                      fullWidth
                      onClick={() => handleStartAddTask(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Heading, Input, Box, Text, Accordion } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const categoryColors: Record<string, { bg: string; light: string }> = {
  'Alkali Metals': {
    bg: 'var(--ggui-color-primary-500, #0ea5e9)',
    light: 'var(--ggui-color-primary-100, #e0f2fe)',
  },
  'Alkaline Earth Metals': {
    bg: 'var(--ggui-color-warning-500, #f59e0b)',
    light: 'var(--ggui-color-warning-100, #fef3c7)',
  },
  'Transition Metals': {
    bg: 'var(--ggui-color-info-500, #06b6d4)',
    light: 'var(--ggui-color-info-100, #cffafe)',
  },
  'Post-transition Metals': {
    bg: 'var(--ggui-color-neutral-500, #6b7280)',
    light: 'var(--ggui-color-neutral-100, #f3f4f6)',
  },
  'Nonmetals': {
    bg: 'var(--ggui-color-success-500, #22c55e)',
    light: 'var(--ggui-color-success-100, #dcfce7)',
  },
  'Halogens': {
    bg: 'var(--ggui-color-error-500, #ef4444)',
    light: 'var(--ggui-color-error-100, #fee2e2)',
  },
  'Noble Gases': {
    bg: 'var(--ggui-color-primary-600, #0284c7)',
    light: 'var(--ggui-color-primary-100, #e0f2fe)',
  },
  'Lanthanides': {
    bg: 'var(--ggui-color-warning-600, #d97706)',
    light: 'var(--ggui-color-warning-200, #fde68a)',
  },
  'Actinides': {
    bg: 'var(--ggui-color-error-600, #dc2626)',
    light: 'var(--ggui-color-error-200, #fecaca)',
  },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);
  const [expandedDetail, setExpandedDetail] = useState<string[]>([]);

  const filteredElements = useMemo(() => {
    return elements.filter((el) => {
      const query = searchQuery.toLowerCase();
      return (el.symbol?.toLowerCase().includes(query)) || (el.name?.toLowerCase().includes(query));
    });
  }, [elements, searchQuery]);

  const visibleCategories = useMemo(() => {
    return [...new Set(filteredElements.map((el) => el.category))].filter(Boolean) as string[];
  }, [filteredElements]);

  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
    setExpandedDetail(['element-detail']);
  };

  const handleDetailChange = (keys: string[]) => {
    setExpandedDetail(keys);
    if (keys.length === 0) {
      setSelectedElement(null);
    }
  };

  const getCategoryColor = (category?: string) => {
    if (!category) {
      return {
        bg: 'var(--ggui-color-neutral-300, #d1d5db)',
        light: 'var(--ggui-color-neutral-100, #f3f4f6)',
      };
    }
    return categoryColors[category] || {
      bg: 'var(--ggui-color-neutral-500, #6b7280)',
      light: 'var(--ggui-color-neutral-100, #f3f4f6)',
    };
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16} direction="vertical">
        <Stack gap={8} direction="vertical">
          <Heading level={2} color="var(--ggui-color-onSurface, #111827)">
            Periodic Table of Elements
          </Heading>
          <Input
            label="Search elements"
            placeholder="Filter by name or symbol (e.g., 'Gold', 'Au')"
            value={searchQuery}
            onChange={setSearchQuery}
            size="md"
          />
        </Stack>

        <Box
          background="var(--ggui-color-surface, #f9fafb)"
          borderRadius={12}
          padding={16}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            border: '1px solid var(--ggui-color-outline, #e5e7eb)',
            minHeight: '600px',
          }}
        >
          {filteredElements.map((element) => {
            const colors = getCategoryColor(element.category);
            const isSelected = selectedElement?.symbol === element.symbol;

            return (
              <div
                key={`${element.atomicNumber}-${element.symbol}`}
                onClick={() => handleElementClick(element)}
                style={{
                  gridRow: element.row || 'auto',
                  gridColumn: element.col || 'auto',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  border: `2px solid ${colors.bg}`,
                  backgroundColor: isSelected ? colors.bg : colors.light,
                  cursor: 'pointer',
                  transition: 'all 200ms ease-in-out',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-1, 4px)',
                  justifyContent: 'center',
                  alignItems: 'center',
                  minHeight: '60px',
                  boxShadow: isSelected
                    ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
