import React, { useEffect, useRef, useState } from 'react';
import { Card, Text, Button } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback when user sends a message (via sendMessage action) */
  onSend?: (payload: { text: string; timestamp: string }) => void;
  /** Action handler for send message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

function formatTime(isoString?: string): string {
  if (!isoString) return '';
  try {
    const date = new Date(isoString);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

function groupConsecutiveMessages(messages: Message[]): Array<Message[]> {
  if (messages.length === 0) return [];

  const groups: Array<Message[]> = [];
  let currentGroup: Message[] = [messages[0]];

  for (let i = 1; i < messages.length; i++) {
    if (messages[i].sender === messages[i - 1].sender) {
      currentGroup.push(messages[i]);
    } else {
      groups.push(currentGroup);
      currentGroup = [messages[i]];
    }
  }
  groups.push(currentGroup);

  return groups;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages, onSend, onSendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on mount and when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = () => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      const payload = { text: inputValue, timestamp };
      // Wire sendMessage action via onSendMessage or onSend
      onSendMessage?.(payload);
      onSend?.(payload);
      setInputValue('');
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const messageGroups = groupConsecutiveMessages(messages);

  return (
    <Card
      padding={0}
      shadow="md"
      border={true}
      radius="lg"
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
        overflow: 'hidden',
      }}
    >
      {/* Header */}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`,
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Text
          variant="label"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="semibold"
        >
          {title}
        </Text>
        {participantCount !== undefined && (
          <div
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
              backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
              color: 'var(--ggui-color-primary-700, #0369a1)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              fontSize: 'var(--ggui-font-size-xs, 12px)',
              fontWeight: 'var(--ggui-font-weight-medium, 500)',
            }}
          >
            {participantCount}
          </div>
        )}
      </div>

      {/* Message List */}
      <div
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-2, 8px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        {messageGroups.map((group, groupIndex) => {
          const sender = group[0]?.sender;
          const isCurrentUser = sender === currentUser;

          return (
            <div
              key={groupIndex}
              style={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              {/* Sender name (only show once per group) */}
              {sender && !isCurrentUser && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  size="xs"
                  as="span"
                >
                  {sender}
                </Text>
              )}

              {/* Message bubbles */}
              <div
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 'var(--ggui-spacing-1, 4px)',
                  alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                  maxWidth: '70%',
                }}
              >
                {group.map((msg, msgIndex) => (
                  <div
                    key={msgIndex}
                    style={{
                      display: 'flex',
                      flexDirection: 'column',
                      gap: 'var(--ggui-spacing-1, 4px)',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      backgroundColor: isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      wordBreak: 'break-word',
                    }}
                  >
                    <Text
                      variant="body"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-neutral-50, #ffffff)'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                      size="sm"
                      as="span"
                    >
                      {msg.text || ''}
                    </Text>
                  </div>
                ))}
              </div>

              {/* Timestamp (only show for last message in group) */}
              {group[group.length - 1]?.timestamp && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  size="xs"
                  as="span"
                >
                  {formatTime(group[group.length - 1].timestamp)}
                </Text>
              )}
            </div>
          );
        })}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div
        style={{
          display: 'flex',
          gap: 'var(--ggui-spacing-2, 8px)',
          padding: 'var(--ggui-spacing-4, 16px)',
          borderTop: `1px solid var(--ggui-color-outline, #d4d4d8)`,
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          alignItems: 'flex-end',
        }}
      >
        <div style={{ flex: 1 }}>
          <label htmlFor="message-input" style={{ display: 'none' }}>
            Type your message
          </label>
          <input
            id="message-input"
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.currentTarget.value)}
            onKeyPress={handleKeyPress}
            placeholder="Type a message..."
            style={{
              width: '100%',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              fontFamily: 'inherit',
              color: 'var(--ggui-color-onSurface, #18181b)',
              backgroundColor: 'var(--ggui-color-surface, #fafafa)',
            }}
          />
        </div>
        <Button
          variant="primary"
          size="md"
          onClick={handleSend}
          disabled={!inputValue.trim()}
          aria-label="Send message"
        >
          Send
        </Button>
      </div>
    </Card>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Spinner,
  Alert,
  Box,
  Divider,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

type ConnectionState = 'idle' | 'connecting' | 'connected' | 'error';

export default function StockTickerDashboard({ stocks: initialStocks = [], lastUpdated: initialTimestamp }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialTimestamp);
  const [connectionState, setConnectionState] = useState<ConnectionState>('idle');
  const [errorMessage, setErrorMessage] = useState<string | undefined>();
  const handlerRef = useRef<(event: Event) => void>();

  // Format price to 2 decimal places
  const formatPrice = useCallback((price?: number): string => {
    if (price === undefined || price === null) return 'N/A';
    return `$${price.toFixed(2)}`;
  }, []);

  // Format change to 2 decimal places
  const formatChange = useCallback((change?: number): string => {
    if (change === undefined || change === null) return '0.00';
    const sign = change > 0 ? '+' : '';
    return `${sign}${change.toFixed(2)}`;
  }, []);

  // Format percentage to 2 decimal places
  const formatPercent = useCallback((percent?: number): string => {
    if (percent === undefined || percent === null) return '0.00';
    const sign = percent > 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  }, []);

  // Determine arrow icon based on change
  const getArrowIcon = useCallback((change?: number): string => {
    if (change === undefined || change === null || change === 0) return '–';
    return change > 0 ? '▲' : '▼';
  }, []);

  // Get color for positive/negative/neutral change
  const getChangeColor = useCallback((change?: number): string => {
    if (change === undefined || change === null || change === 0) {
      return 'var(--ggui-color-neutral-600, #4b5563)';
    }
    return change > 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  }, []);

  // Get border color for card based on change
  const getBorderColor = useCallback((change?: number): string => {
    if (change === undefined || change === null || change === 0) {
      return 'var(--ggui-color-neutral-300, #d1d5db)';
    }
    return change > 0
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  }, []);

  // Format timestamp to human-readable format
  const formatTimestamp = useCallback((timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return '';
    }
  }, []);

  // Set up event listener for live data updates (Stream Contract)
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.stocks) {
        setStocks(customEvent.detail.stocks);
        setConnectionState('connected');
        setLastUpdated(new Date().toISOString());
        setErrorMessage(undefined);
      }
    };

    handlerRef.current = handleAgentData;

    // Simulate connection state transition
    setConnectionState('connecting');

    if (typeof window !== 'undefined') {
      window.addEventListener('ggui:agent-data', handleAgentData);
    }

    return () => {
      if (typeof window !== 'undefined' && handlerRef.current) {
        window.removeEventListener('ggui:agent-data', handlerRef.current);
      }
    };
  }, []);

  // If stocks provided initially, mark as connected
  useEffect(() => {
    if (initialStocks.length > 0 && connectionState === 'idle') {
      setConnectionState('connected');
      setStocks(initialStocks);
      setLastUpdated(initialTimestamp);
    }
  }, [initialStocks, connectionState, initialTimestamp]);

  // Connecting state - show spinner overlay
  if (connectionState === 'connecting' && stocks.length === 0) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack direction="vertical" gap={24} align="center" justify="center">
          <Spinner size={48} color="var(--ggui-color-primary-600, #0284c7)" />
          <Text variant="body">Connecting to live feed...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack direction="vertical" gap={24}>
        {/* Header with title and last updated */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>
          {lastUpdated && (
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              aria-label={`Last updated at ${formatTimestamp(lastUpdated)}`}
            >
              Last Updated: {formatTimestamp(lastUpdated)}
            </Text>
          )}
        </Stack>

        {/* Live status badge */}
        {connectionState === 'connected' && stocks.length > 0 && (
          <Badge variant="success" size="sm" pill>
            ● LIVE
          </Badge>
        )}

        {/* Error alert */}
        {connectionState === 'error' && (
          <Alert
            variant="error"
            title="Connection Error"
            closable
            onClose={() => setConnectionState('idle')}
          >
            {errorMessage || 'Unable to connect to live feed. Please refresh the page.'}
          </Alert>
        )}

        {/* Empty state when connected but no data */}
        {stocks.length === 0 && connectionState === 'connected' && (
          <Stack direction="vertical" align="center" justify="center" gap={16}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              No market data available
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Waiting for stock updates...
            </Text>
            <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
          </Stack>
        )}

        {/* Responsive grid of stock cards */}
        {stocks.length > 0 && (
          <Box
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {stocks.map((stock, index) => {
              const borderColor = getBorderColor(stock.change);
              const changeColor = getChangeColor(stock.change);
              const arrow = getArrowIcon(stock.change);

              return (
                <div
                  key={stock.symbol || index}
                  role="article"
                  aria-label={`${stock.symbol} stock card - ${stock.name}`}
                  style={{
                    animation: `ggui-fadeIn 400ms ease-out ${index * 50}ms both`,
                  }}
                >
                  <Card
                    shadow="md"
                    padding={20}
                    radius="lg"
                    border
                    style={{
                      borderColor: borderColor,
                      borderWidth: '2px',
                      transition: 'border-color 300ms ease, box-shadow 200ms ease',
                    }}
                  >
                    <Stack direction="vertical" gap={12}>
                      {/* Ticker symbol - large and bold */}
                      <Heading
                        level={4}
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {stock.symbol || 'N/A'}
                      </Heading>

                      {/* Company name */}
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {stock.name || 'Unknown Company'}
                      </Text>

                      {/* Visual divider */}
                      <Divider margin={8} color="var(--ggui-color-outline, #d4d4d8)" />

                      {/* Price and change section */}
                      <Stack direction="vertical" gap={8}>
                        {/* Current price */}
                        <Text
                          size="2xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {formatPrice(stock.price)}
                        </Text>

                        {/* Change row: arrow + change amount + percentage */}
                        <Stack direction="horizontal" align="center" gap={4}>
                          <Text
                            as="span"
                            size="lg"
                            weight="bold"
                            color={changeColor}
                            style={{ minWidth: '16px', textAlign: 'center' }}
                          >
                            {arrow}
                          </Text>
                          <Text as="span" size="sm" color={changeColor}>
                            {formatChange(stock.change)}
                          </Text>
                          <Text as="span" size="sm" color={changeColor}>
                            ({formatPercent(stock.changePercent)})
                          </Text>
                        </Stack>
                      </Stack>
                    </Stack>
                  </Card>
                </div>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Button,
  Progress,
  Divider,
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback when setup is complete */
  onComplete?: (profileData: ProfileData) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(initialProfile?.name || '');
  const [email, setEmail] = useState(initialProfile?.email || '');
  const [selectedAvatar, setSelectedAvatar] = useState(initialProfile?.avatar || avatarOptions[0] || '👤');
  const [role, setRole] = useState(initialProfile?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? false);
  const [theme, setTheme] = useState(initialProfile?.theme || 'light');
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  // Validation
  const validateEmail = (emailValue: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(emailValue);
  };

  const validateName = (nameValue: string): boolean => {
    return nameValue.trim().length >= 2;
  };

  const validateStep1 = (): boolean => {
    const newErrors: { name?: string; email?: string } = {};

    if (!name.trim()) {
      newErrors.name = 'Name is required';
    } else if (!validateName(name)) {
      newErrors.name = 'Name must be at least 2 characters';
    }

    if (!email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(email)) {
      newErrors.email = 'Please enter a valid email address';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handlers
  const handleNext = () => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
        setErrors({});
      }
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  };

  const handleComplete = () => {
    if (onComplete) {
      onComplete({
        name,
        email,
        avatar: selectedAvatar,
        role,
        emailNotifications,
        theme,
      });
    }
  };

  // Build role options for Select
  const roleSelectOptions = useMemo(
    () => roleOptions.map((r) => ({ value: r, label: r })),
    [roleOptions]
  );

  // Progress calculation
  const progress = (currentStep / 3) * 100;

  // Render Step Indicator
  const renderStepIndicator = () => (
    <Stack gap={16} align="center">
      <Stack direction="horizontal" gap={8} align="center" justify="center">
        {[1, 2, 3].map((step) => (
          <div key={step} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
            <div
              style={{
                width: 40,
                height: 40,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                backgroundColor:
                  step < currentStep
                    ? 'var(--ggui-color-success-500, #22c55e)'
                    : step === currentStep
                    ? 'var(--ggui-color-primary-600, #0284c7)'
                    : 'var(--ggui-color-neutral-200, #e5e7eb)',
                color:
                  step === currentStep || step < currentStep
                    ? 'white'
                    : 'var(--ggui-color-neutral-500, #6b7280)',
                transition: 'all 0.3s ease-out',
              }}
            >
              {step < currentStep ? '✓' : step}
            </div>
            {step < 3 && (
              <div
                style={{
                  width: 24,
                  height: 2,
                  backgroundColor:
                    step < currentStep
                      ? 'var(--ggui-color-success-500, #22c55e)'
                      : 'var(--ggui-color-neutral-200, #e5e7eb)',
                  transition: 'background-color 0.3s ease-out',
                }}
              />
            )}
          </div>
        ))}
      </Stack>

      <Progress value={progress} max={100} variant="default" size="md" />
    </Stack>
  );

  // Render Step 1
  const renderStep1 = () => (
    <Stack gap={20}>
      <div>
        <Heading level={3}>Create Your Profile</Heading>
        <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
          Let's get to know you
        </Text>
      </div>

      <Input
        label="Full Name"
        placeholder="John Doe"
        value={name}
        onChange={setName}
        required
        error={errors.name}
        size="md"
      />

      <Input
        label="Email Address"
        type="email"
        placeholder="you@example.com"
        value={email}
        onChange={setEmail}
        required
        error={errors.email}
        size="md"
      />

      <div>
        <Text variant="label" style={{ display: 'block', marginBottom: 'var(--ggui-spacing-2, 8px)' }}>
          Choose Avatar
        </Text>
        <Stack direction="horizontal" gap={12}>
          {avatarOptions.map((avatar) => (
            <Button
              key={avatar}
              variant={selectedAvatar === avatar ? 'primary' : 'ghost'}
              size="lg"
              onClick={() => setSelectedAvatar(avatar)}
              style={{
                fontSize: '24px',
                padding: 'var(--ggui-spacing-2, 8px)',
                minWidth: 'auto',
              }}
            >
              {avatar}
            </Button>
          ))}
        </Stack>
      </div>
    </Stack>
  );

  // Render Step 2
  const renderStep2 = () => (
    <Stack gap={20}>
      <div>
        <Heading level={3}>Your Preferences</Heading>
        <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
          Customize your experience
        </Text>
      </div>

      <Select
        label="Your Role"
        placeholder="Select a role"
        value={role}
        onChange={setRole}
        options={roleSelectOptions}
        size="md"
      />

      <Toggle label="Enable email notifications" checked={emailNotifications} onChange={setEmailNotifications} size="md" />

      <RadioGroup
        label="Theme Preference"
        value={theme}
        onChange={setTheme}
        options={[
          { value: 'light', label: 'Light' },
          { value: 'dark', label: 'Dark' },
        ]}
        direction="horizontal"
      />
    </Stack>
  );

  // Render Step 3 (Review)
  const renderStep3 = () => (
    <Stack gap={20}>
      <div>
        <Heading level={3}>Review & Confirm</Heading>
        <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
          Please verify your information
        </Text>
      </div>

      <Stack gap={16}>
        {/* Summary Items */}
        <div style={{ display: 'grid', gap: 'var(--ggui-spacing-2, 8px)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
            <Stack direction="horizontal" gap={8} align="center">
              <Text style={{ fontSize: '20px' }}>👤</Text>
              <Stack gap={2}>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Name
                </Text>
                <Text variant="body">{name}</Text>
              </Stack>
            </Stack>
          </div>

          <Divider />

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
            <Stack direction="horizontal" gap={8} align="center">
              <Text style={{ fontSize: '20px' }}>✉️</Text>
              <Stack gap={2}>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Email
                </Text>
                <Text variant="body">{email}</Text>
              </Stack>
            </Stack>
          </div>

          <Divider />

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
            <Stack direction="horizontal" gap={8} align="center">
              <Text style={{ fontSize: '20px' }}>👔</Text>
              <Stack gap={2}>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Role
                </Text>
                <Text variant="body">{role || 'Not selected'}</Text>
              </Stack>
            </Stack>
          </div>

          <Divider />

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
            <Stack direction="horizontal" gap={8} align="center">
              <Text style={{ fontSize: '20px' }}>🔔</Text>
              <Stack gap={2}>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Notifications
                </Text>
                <Text variant="body">{emailNotifications ? 'Enabled' : 'Disabled'}</Text>
              </Stack>
            </Stack>
          </div>

          <Divider />

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: 'var(--ggui-spacing-2, 8px) 0' }}>
            <Stack direction="horizontal" gap={8} align="center">
              <Text style={{ fontSize: '20px' }}>🎨</Text>
              <Stack gap={2}>
                <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
                  Theme
                </Text>
                <Text variant="body" style={{ textTransform: 'capitalize' }}>
                  {theme || 'Not selected'}
                </Text>
              </Stack>
            </Stack>
          </div>
        </div>

        {/* Edit Link */}
        <Button variant="ghost" size="sm" onClick={() => setCurrentStep(1)}>
          ← Edit Profile
        </Button>
      </Stack>
    </Stack>
  );

  // Main render
  return (
    <div style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)', minHeight: '100vh', padding: 'var(--ggui-spacing-6, 24px) 0' }}>
      <Container maxWidth="md" padding={0}>
        <Stack gap={32}>
          {/* Step Indicator */}
          {renderStepIndicator()}

          {/* Content Card */}
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={24}>
              {currentStep === 1 && renderStep1()}
              {currentStep === 2 && renderStep2()}
              {currentStep === 3 && renderStep3()}
            </Stack>
          </Card>

          {/* Navigation */}
          <Stack direction="horizontal" gap={12} justify="between" align="center">
            <Button
              variant="outline"
              size="md"
              onClick={handleBack}
              disabled={currentStep === 1}
            >
              Go Back
            </Button>

            <Button
              variant="primary"
              size="md"
              onClick={currentStep === 3 ? handleComplete : handleNext}
            >
              {currentStep === 3 ? 'Complete Setup' : 'Next'}
            </Button>
          </Stack>
        </Stack>
      </Container>
    </div>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Avatar, Select, Alert } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: string; taskId: string; data: Record<string, unknown> }) => void;
  onSubmit?: (payload: { title: string; priority: 'low' | 'medium' | 'high' }) => Promise<void> | void;
}

type TaskItem = {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  column: string;
  dueDate?: string;
};

export default function GeneratedComponent({
  tasks = [
    { id: 't1', title: 'Draft requirements', priority: 'high', assignee: 'AL', column: 'todo', dueDate: '2026-04-01' },
    { id: 't2', title: 'Build UI prototype', priority: 'medium', assignee: 'BK', column: 'in-progress' },
    { id: 't3', title: 'QA validation', priority: 'low', assignee: 'CM', column: 'done' },
  ],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  taskUpdate,
  onSubmit,
}: Props) {
  const normalizedTasks = useMemo<TaskItem[]>(
    () =>
      tasks.map((t, idx) => ({
        id: t.id || `task-${idx + 1}`,
        title: t.title || `Untitled Task ${idx + 1}`,
        priority: t.priority || 'low',
        assignee: t.assignee,
        column: t.column || (columns[0]?.id || 'todo'),
        dueDate: t.dueDate,
      })),
    [tasks, columns]
  );

  const [boardTasks, setBoardTasks] = useState<TaskItem[]>(normalizedTasks);
  const [editingId, setEditingId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [addForColumn, setAddForColumn] = useState<string>('');
  const [newTitle, setNewTitle] = useState<string>('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [formError, setFormError] = useState<string>('');
  const [submitState, setSubmitState] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

  const totalTasks = boardTasks.length;
  const doneColumnId = columns.find((c) => c.name?.toLowerCase() === 'done')?.id || 'done';
  const completedTasks = boardTasks.filter((t) => t.column === doneColumnId).length;

  const priorityVariant = (p: 'low' | 'medium' | 'high') =>
    p === 'high' ? 'error' : p === 'medium' ? 'warning' : 'success';

  const moveTask = (taskId: string, nextColumn: string) => {
    setBoardTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: nextColumn } : t))
    );
    taskUpdate?.({ action: 'move', taskId, data: { column: nextColumn } });
  };

  const saveEdit = (taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
    setBoardTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: trimmed } : t))
    );
    taskUpdate?.({ action: 'edit', taskId, data: { title: trimmed } });
    setEditingId('');
    setEditingTitle('');
  };

  const submitNewTask = async (columnId: string) => {
    const trimmed = newTitle.trim();
    if (!trimmed) {
      setFormError('Title is required.');
      return;
    }

    setFormError('');
    setSubmitState('submitting');

    try {
      await onSubmit?.({ title: trimmed, priority: newPriority });
      const created: TaskItem = {
        id: `task-${Date.now()}`,
        title: trimmed,
        priority: newPriority,
        column: columns[0]?.id || 'todo',
      };
      setBoardTasks((prev) => [...prev, created]);
      taskUpdate?.({ action: 'create', taskId: created.id, data: created });
      setSubmitState('success');
      setNewTitle('');
      setNewPriority('medium');
      setAddForColumn('');
      setTimeout(() => setSubmitState('idle'), 1400);
    } catch (e) {
      setSubmitState('error');
    }
  };

  return (
    <Stack gap={16}>
      <Card
        padding={12}
        border
        shadow="sm"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="center">
          <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            Total Tasks: {totalTasks}
          </Text>
          <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            Completed: {completedTasks}
          </Text>
        </Stack>
      </Card>

      {submitState === 'success' && <Alert variant="success" title="Success">Task created successfully.</Alert>}
      {submitState === 'error' && <Alert variant="error" title="Error">Failed to submit task.</Alert>}

      <Stack direction="horizontal" gap={12} align="start" wrap>
        {columns.map((col) => {
          const columnId = col.id || '';
          const columnTasks = boardTasks.filter((t) => t.column === columnId);

          return (
            <Card
              key={columnId}
              padding={12}
              border
              shadow="sm"
              style={{
                minWidth: '280px',
                flex: 1,
                background: 'var(--ggui-color-surface, #fafafa)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={10}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    {col.name || 'Column'}
                  </Text>
                  <Badge variant="default" size="sm">
                    {columnTasks.length}
                  </Badge>
                </Stack>

                <Stack gap={8}>
                  {columnTasks.map((task) => (
                    <Card
                      key={task.id}
                      padding={10}
                      border
                      shadow="none"
                      style={{
                        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                      }}
                    >
                      <Stack gap={8}>
                        {editingId === task.id ? (
                          <Stack direction="horizontal" gap={8} align="center">
                            <Input
                              aria-label="Edit task title"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              placeholder="Task title"
                              size="sm"
                            />
                            <Button size="sm" onClick={() => saveEdit(task.id)}>Save</Button>
                          </Stack>
                        ) : (
                          <Stack direction="horizontal" justify="between" align="center">
                            <Text
                              weight="medium"
                              color="var(--ggui-color-onSurface, #18181b)"
                              as="div"
                              onDoubleClick={() => {
                                setEditingId(task.id);
                                setEditingTitle(task.title);
                              }}
                            >
                              {task.title}
                            </Text>
                            <Button
                              variant="ghost"
                              size="xs"
                              aria-label={`Edit ${task.title}`}
                              onClick={() => {
                                setEditingId(task.id);
                                setEditingTitle(task.title);
                              }}
                            >
                              Edit
                            </Button>
                          </Stack>
                        )}

                        <Stack direction="horizontal" justify="between" align="center">
                          <Badge variant={priorityVariant(task.priority)} size="sm">
                            {task.priority.toUpperCase()}
                          </Badge>
                          <Avatar name={task.assignee || 'U'} size="xs" />
                        </Stack>

                        {task.dueDate ? (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            Due: {task.dueDate}
                          </Text>
                        ) : null}

                        <Select
                          label="Move task"
                          value={task.column}
                          onChange={(value) => moveTask(task.id, value)}
                          options={columns
                            .filter((c) => (c.id || '') !== task.column)
                            .map((c) => ({ value: c.id || '', label: c.name || 'Column' }))}
                          placeholder="Select column"
                          size="sm"
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addForColumn === columnId ? (
                  <Card
                    padding={10}
                    border
                    shadow="none"
                    style={{
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                    }}
                  >
                    <Stack gap={8}>
                      <Input
                        label="Task title"
                        value={newTitle}
                        onChange={setNewTitle}
                        required
                        error={formError}
                        placeholder="Enter task title"
                      />
                      <Select
                        label="Priority"
                        value={newPriority}
                        onChange={(v) => setNewPriority(v as 'low' | 'medium' | 'high')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Stack direction="horizontal" gap={8}>
                        <Button
                          variant="primary"
                          size="sm"
                          loading={submitState === 'submitting'}
                          disabled={submitState === 'submitting' || !newTitle.trim()}
                          onClick={() => submitNewTask(columnId)}
                        >
                          Submit
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          disabled={submitState === 'submitting'}
                          onClick={() => {
                            setAddForColumn('');
                            setFormError('');
                          }}
                        >
                          Cancel
                        </Button>
                      </Stack>
                    </Stack>
                  </Card>
                ) : (
                  <Button
                    variant="outline"
                    size="sm"
                    fullWidth
                    onClick={() => {
                      setAddForColumn(columnId);
                      setNewTitle('');
                      setNewPriority('medium');
                      setFormError('');
                    }}
                  >
                    Add Task
                  </Button>
                )}
              </Stack>
            </Card>
          );
        })}
      </Stack>
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const defaultProps: Props = {
  elements: [],
};

export default function GeneratedComponent(props: Props) {
  const { elements } = { ...defaultProps, ...props };
  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColorMap: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
    'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
    'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
    metalloid: 'var(--ggui-color-success-500, #22c55e)',
    nonmetal: 'var(--ggui-color-success-600, #16a34a)',
    halogen: 'var(--ggui-color-warning-600, #d97706)',
    'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
    lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
    actinide: 'var(--ggui-color-error-600, #dc2626)',
    unknown: 'var(--ggui-color-neutral-500, #6b7280)',
  };

  const normalizedElements = useMemo(
    () =>
      elements.map((el) => ({
        ...el,
        name: el.name ?? 'Unknown',
        symbol: el.symbol ?? '?',
        category: (el.category ?? 'unknown').toLowerCase(),
        atomicNumber: el.atomicNumber ?? 0,
        atomicWeight: el.atomicWeight ?? 0,
        row: el.row ?? 1,
        col: el.col ?? 1,
      })),
    [elements]
  );

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return normalizedElements;
    return normalizedElements.filter(
      (el) =>
        (el.name ?? '').toLowerCase().includes(q) ||
        (el.symbol ?? '').toLowerCase().includes(q)
    );
  }, [normalizedElements, search]);

  const selectedElement =
    normalizedElements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;

  const legendItems = useMemo(() => {
    const seen = new Set<string>();
    const categories: string[] = [];
    normalizedElements.forEach((el) => {
      const c = (el.category ?? 'unknown').toLowerCase();
      if (!seen.has(c)) {
        seen.add(c);
        categories.push(c);
      }
    });
    return categories.sort();
  }, [normalizedElements]);

  return (
    <Card
      padding={16}
      border
      shadow="sm"
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text variant="label" size="xl" color="var(--ggui-color-onSurface, #18181b)">
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          placeholder="Search by name or symbol"
          value={search}
          onChange={setSearch}
          type="search"
          aria-label="Search elements by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            overflowX: 'auto',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(52px, 1fr))',
              gridAutoRows: '64px',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '980px',
            }}
          >
            {filteredElements.map((el) => {
              const bg =
                categoryColorMap[el.category ?? 'unknown'] ??
                'var(--ggui-color-neutral-500, #6b7280)';
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <button
                  key={`${el.atomicNumber}-${el.symbol}`}
                  type="button"
                  role="gridcell"
                  aria-label={`${el.name} (${el.symbol}), atomic number ${el.atomicNumber}`}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  style={{
