import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: send outgoing message payload */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [draft, setDraft] = useState<string>('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && (last.sender || '') === (msg.sender || '')) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTimestamp = (iso?: string) => {
    if (!iso) return '';
    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const payload = customEvent.detail;
      if (payload && (payload.text || payload.sender || payload.timestamp)) {
        setStreamMessages((prev) => [...prev, payload]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handler as EventListener);
    };
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setDraft('');
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        height: '100%',
        minHeight: '420px',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" pill>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Stack
          gap={0}
          style={{
            flex: 1,
            minHeight: 0,
          }}
        >
          <Stack
            gap="var(--ggui-spacing-2, 8px)"
            style={{
              flex: 1,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            ref={listRef}
            aria-label="Message list"
          >
            {groupedMessages.map((group, groupIndex) => {
              const isOwn = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  align={isOwn ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ paddingInline: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {group.sender || ''}
                  </Text>
                  <Stack gap="var(--ggui-spacing-1, 4px)" align={isOwn ? 'end' : 'start'}>
                    {group.items.map((item, itemIndex) => (
                      <Stack
                        key={`${item.sender || 'unknown'}-${item.timestamp || itemIndex}-${itemIndex}`}
                        gap={2}
                        style={{
                          maxWidth: '80%',
                          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: isOwn
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          color: isOwn
                            ? 'var(--ggui-color-surface, #fafafa)'
                            : 'var(--ggui-color-onSurface, #18181b)',
                          transition: 'background-color 200ms ease-in-out',
                        }}
                      >
                        <Text
                          variant="bodySmall"
                          color={
                            isOwn
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurface, #18181b)'
                          }
                        >
                          {item.text || ''}
                        </Text>
                        <Text
                          variant="caption"
                          color={
                            isOwn
                              ? 'var(--ggui-color-primary-100, #e0f2fe)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                          align="right"
                        >
                          {formatTimestamp(item.timestamp)}
                        </Text>
                      </Stack>
                    ))}
                  </Stack>
                </Stack>
              );
            })}
          </Stack>
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Input
            aria-label="Compose message"
            placeholder={title}
            value={draft}
            onChange={setDraft}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
            size="md"
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [hasStreamData, setHasStreamData] = useState<boolean>(false);

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const timeout = window.setTimeout(() => {
      if (!hasStreamData) setIsConnecting(true);
    }, 800);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;

      const incoming = customEvent.detail;
      if (!incoming) return;

      setIsConnecting(false);
      setHasStreamData(true);

      if (Array.isArray(incoming.stocks)) {
        setLiveStocks(incoming.stocks);
      }
      if (typeof incoming.lastUpdated === 'string') {
        setLiveLastUpdated(incoming.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.clearTimeout(timeout);
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, [hasStreamData]);

  const formattedLastUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  const isLoading = liveStocks.length === 0;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack direction="horizontal" justify="between" align="center">
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {isConnecting && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
              aria-live="polite"
            >
              {isConnecting ? 'Connecting live feed…' : `Last Updated: ${formattedLastUpdated}`}
            </Text>
          </Stack>
        </Stack>

        {isLoading ? (
          <Card
            padding="var(--ggui-spacing-8, 32px)"
            shadow="none"
            border
            radius="md"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
            }}
          >
            <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
              <Spinner size={24} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Loading stock prices…
              </Text>
            </Stack>
          </Card>
        ) : (
          <div
            role="list"
            aria-label="Stock ticker grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {liveStocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const trendColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const trendArrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={`${stock.symbol ?? 'stock'}-${index}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: trendColor,
                    transition:
                      'border-color 200ms ease-in-out, box-shadow 200ms ease-in-out, transform 200ms ease-in-out',
                  }}
                  role="listitem"
                  aria-label={`${stock.symbol ?? 'N/A'} stock card`}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="3xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol ?? '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {stock.name ?? 'Unknown Company'}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${(stock.price ?? 0).toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text variant="label" color={trendColor}>
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text variant="label" color={trendColor}>
                        {trendArrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ['😀', '😎', '🚀', '🌟'],
  roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
  complete = () => {},
}: Props) {
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? (avatarOptions[0] ?? ''));
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const onNext = () => {
    if (step < 3 && canNext) setStep((s) => s + 1);
  };

  const onBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const onSubmit = () => {
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          maxWidth: 'var(--ggui-size-onboarding-maxWidth, 640px)',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
              transition: motionEnabled ? 'opacity 200ms ease-in-out, transform 200ms ease-in-out' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold">
                  Profile Setup
                </Text>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                  aria-label="Name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={email.trim().length === 0 ? 'Email is required' : !emailValid ? 'Enter a valid email' : undefined}
                  aria-label="Email"
                />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.slice(0, 4).map((opt) => {
                      const selected = avatar === opt;
                      return (
                        <Button
                          key={opt}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          onClick={() => setAvatar(opt)}
                          aria-label={`Select avatar ${opt}`}
                        >
                          {opt}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold">
                  Preferences
                </Text>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  required
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                  aria-label="Role"
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold">
                  Review & Confirm
                </Text>
                <Card
                  padding={16}
                  radius="md"
                  shadow="none"
                  border
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Stack gap={8}>
                    <Text><strong>Name:</strong> {name}</Text>
                    <Text><strong>Email:</strong> {email}</Text>
                    <Text><strong>Avatar:</strong> {avatar}</Text>
                    <Text><strong>Role:</strong> {role}</Text>
                    <Text><strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between" align="center" gap={12}>
            <Button variant="ghost" onClick={onBack} disabled={step === 1} aria-label="Go Back">
              Go Back
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={onNext} disabled={!canNext} aria-label="Next">
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={onSubmit} aria-label="Complete Setup">
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = 'City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const normalizedUnit = unit || 'C';
  const displayForecast = forecast.slice(0, 5);

  const getConditionIcon = (value: string): string => {
    const normalized = value.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rainy') || normalized.includes('drizzle')) return '🌧️';
    if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('snowy') || normalized.includes('snow')) return '❄️';
    if (normalized.includes('mist') || normalized.includes('fog')) return '🌫️';
    return '🌤️';
  };

  const currentIcon = getConditionIcon(condition);

  return (
    <Card
      padding={24}
      shadow="md"
      radius="xl"
      border
      role="region"
      aria-label={`Weather for ${city}`}
    >
      <Stack
        direction="vertical"
        gap={16}
        style={{
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="start" wrap>
          <Stack direction="vertical" gap={8}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>

            <Stack direction="horizontal" gap={8} align="center">
              <Box
                padding="var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)"
                background="var(--ggui-color-container, #ede9fe)"
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Text
                  as="span"
                  variant="body"
                  color="var(--ggui-color-onContainer, #4c1d95)"
                  aria-label={`${condition} icon`}
                >
                  {currentIcon}
                </Text>
              </Box>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>
          </Stack>

          <Text
            variant="body"
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-700, #0369a1)"
          >
            {temperature}°{normalizedUnit}
          </Text>
        </Stack>

        <Stack direction="horizontal" gap={16} justify="between" wrap>
          <Box
            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              minWidth: '140px',
              flex: '1 1 160px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-surface, #fafafa)"
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              minWidth: '140px',
              flex: '1 1 160px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed}
              </Text>
            </Stack>
          </Box>
        </Stack>

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Box
          padding="var(--ggui-spacing-2, 8px)"
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          aria-label="5-day forecast"
          style={{
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack direction="horizontal" gap={8} wrap>
            {displayForecast.map((item, index) => {
              const day = item.day || '—';
              const icon = item.icon || getConditionIcon(condition);
              const high =
                typeof item.high === 'number' ? `${item.high}°` : '—';
              const low =
                typeof item.low === 'number' ? `${item.low}°` : '—';

              return (
                <Box
                  key={`${day}-${index}`}
                  padding="var(--ggui-spacing-2, 8px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  aria-label={`${day}: high ${high}, low ${low}`}
                  style={{
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    minWidth: '92px',
                    flex: '1 1 92px',
                    transition:
                      'box-shadow 200ms ease, transform 200ms ease',
                  }}
                >
                  <Stack direction="vertical" gap={4} align="center">
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day}
                    </Text>
                    <Text as="span" variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                      {icon}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      {high}/{low}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Avatar,
  Badge,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  Select,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  onSubmit?: (payload: { action: string; taskId?: string; data: Record<string, unknown> }) => Promise<void> | void;
}

const getPriorityBadgeVariant = (priority: 'low' | 'medium' | 'high') => {
  if (priority === 'low') return 'success';
  if (priority === 'high') return 'error';
  return 'warning';
};

export default function GeneratedComponent({
  tasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  onSubmit,
}: Props) {
  const [localTasks, setLocalTasks] = useState<Props['tasks']>(tasks);
  const [addFormByColumn, setAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [newTaskTitleErrorByColumn, setNewTaskTitleErrorByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityErrorByColumn, setNewTaskPriorityErrorByColumn] = useState<Record<string, string>>({});
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [editingTitleError, setEditingTitleError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState<string | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  useEffect(() => {
    if (!submitSuccess) return;
    const timer = window.setTimeout(() => setSubmitSuccess(null), 2200);
    return () => window.clearTimeout(timer);
  }, [submitSuccess]);

  const normalizedColumns = useMemo(
    () =>
      columns.map((column, index) => ({
        id: column.id || `column-${index}`,
        name: column.name || `Column ${index + 1}`,
      })),
    [columns]
  );

  const defaultCreateColumnId = normalizedColumns[0]?.id || 'todo';
  const totalTasks = localTasks.length;
  const completedCount = localTasks.filter((t) => t.column === 'done').length;

  const openAddForm = (columnId: string) => {
    setSubmitError(null);
    setSubmitSuccess(null);
    setAddFormByColumn((prev) => ({ ...prev, [columnId]: true }));
    setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || 'medium' }));
  };

  const closeAddForm = (columnId: string) => {
    setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
    setNewTaskTitleErrorByColumn((prev) => ({ ...prev, [columnId]: '' }));
    setNewTaskPriorityErrorByColumn((prev) => ({ ...prev, [columnId]: '' }));
  };

  const updateTask = async (payload: { action: string; taskId?: string; data: Record<string, unknown> }) => {
    setSubmitting(true);
    setSubmitError(null);
    try {
      await onSubmit?.(payload);
      setSubmitSuccess('Task updated successfully.');
    } catch {
      setSubmitError('Unable to submit task update. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleMoveTask = async (taskId: string, destinationColumnId: string) => {
    setLocalTasks((prev) =>
      prev.map((task) => (task.id === taskId ? { ...task, column: destinationColumnId } : task))
    );
    await updateTask({ action: 'move', taskId, data: { column: destinationColumnId } });
  };

  const startEditing = (taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
    setEditingTitleError(null);
    setSubmitError(null);
    setSubmitSuccess(null);
  };

  const cancelEditing = () => {
    setEditingTaskId(null);
    setEditingTitle('');
    setEditingTitleError(null);
  };

  const saveEditing = async (taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) {
      setEditingTitleError('Task title is required.');
      return;
    }
    setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
    await updateTask({ action: 'edit', taskId, data: { title: trimmed } });
    cancelEditing();
  };

  const handleCreateTask = async (columnId: string) => {
    const title = (newTaskTitleByColumn[columnId] || '').trim();
    const priority = newTaskPriorityByColumn[columnId] || 'medium';

    let hasError = false;
    if (!title) {
      hasError = true;
      setNewTaskTitleErrorByColumn((prev) => ({ ...prev, [columnId]: 'Task title is required.' }));
    } else {
      setNewTaskTitleErrorByColumn((prev) => ({ ...prev, [columnId]: '' }));
    }

    if (!priority) {
      hasError = true;
      setNewTaskPriorityErrorByColumn((prev) => ({ ...prev, [columnId]: 'Priority is required.' }));
    } else {
      setNewTaskPriorityErrorByColumn((prev) => ({ ...prev, [columnId]: '' }));
    }

    if (hasError) return;

    const newId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const newTask = {
      id: newId,
      title,
      priority,
      assignee: '',
      column: defaultCreateColumnId || columnId || 'todo',
      dueDate: '',
    };

    setLocalTasks((prev) => [...prev, newTask]);

    try {
      setSubmitting(true);
      setSubmitError(null);
      await onSubmit?.({
        action: 'create',
        taskId: newId,
        data: { title, priority, column: newTask.column },
      });
      setSubmitSuccess('Task created successfully.');
      setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
      setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'medium' }));
    } catch {
      setSubmitError('Unable to create task. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap={16}>
        <Card shadow="sm" radius="lg" padding={16} border>
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              Kanban Task Board
            </Heading>
            <Stack direction="horizontal" gap={8} align="center">
              <Card
                shadow="none"
                border
                radius="md"
                padding="var(--ggui-spacing-2, 8px)"
                style={{ background: 'var(--ggui-color-container, #ede9fe)' } as React.CSSProperties}
              >
                <Text variant="label" color="var(--ggui-color-onContainer, #4c1d95)">
                  Total: {totalTasks}
                </Text>
              </Card>
              <Card
                shadow="none"
                border
                radius="md"
                padding="var(--ggui-spacing-2, 8px)"
                style={{ background: 'var(--ggui-color-container, #ede9fe)' } as React.CSSProperties}
              >
                <Text variant="label" color="var(--ggui-color-onContainer, #4c1d95)">
                  Completed: {completedCount}
                </Text>
              </Card>
            </Stack>
          </Stack>
        </Card>

        {(submitSuccess || submitError) && (
          <Alert variant={submitError ? 'error' : 'success'} title={submitError ? 'Error' : 'Success'}>
            {submitError || submitSuccess}
          </Alert>
        )}

        <Divider color="var(--ggui-color-outlineVariant, #e4e4e7)" margin={0} />

        <Stack
          direction="horizontal"
          wrap
          gap={16}
          align="start"
          justify="start"
          role="region"
          aria-label="Kanban task board"
        >
          {normalizedColumns.map((column) => {
            const columnTasks = localTasks.filter((task) => (task.column || defaultCreateColumnId) === column.id);
            const columnHeadingId = `kanban-column-heading-${column.id}`;
            const isAddOpen = !!addFormByColumn[column.id];

            return (
              <Card
                key={column.id}
                shadow="sm"
                radius="lg"
                padding={12}
                border
                role="region"
                aria-labelledby={columnHeadingId}
                style={
                  {
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                    flex: '1 1 280px',
                    minWidth: '280px',
                  } as React.CSSProperties
                }
              >
                <Stack gap={12}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading id={columnHeadingId} level={6} color="var(--ggui-color-onSurface, #18181b)">
                      {column.name}
                    </Heading>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {columnTasks.length}
                    </Text>
                  </Stack>

                  <Stack gap={12} role="list" aria-label={`${column.name} tasks`}>
                    {columnTasks.length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        No tasks in this column.
                      </Text>
                    )}

                    {columnTasks.map((task, index) => {
                      const taskId = task.id || `task-${column.id}-${index}`;
                      const title = task.title || 'Untitled task';
                      const priority = task.priority || 'medium';
                      const isEditing = editingTaskId === taskId;
                      const assigneeName = task.assignee || title;

                      return (
                        <Card
                          key={taskId}
                          shadow="sm"
                          radius="md"
                          padding={12}
                          border
                          role="listitem"
                          style={
                            {
                              background: 'var(--ggui-color-surface, #fafafa)',
                              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                            } as React.CSSProperties
                          }
                        >
                          <Stack gap={10}>
                            <Stack direction="horizontal" justify="between" align="start" gap={8}>
                              {isEditing ? (
                                <Input
                                  label="Task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  error={editingTitleError || undefined}
                                  required
                                  size="sm"
                                  onKeyDown={(e) => {
                                    if (e.key === 'Escape') cancelEditing();
                                    if (e.key === 'Enter') void saveEditing(taskId);
                                  }}
                                />
                              ) : (
                                <Text
                                  variant="label"
                                  color="var(--ggui-color-onSurface, #18181b)"
                                  as="div"
                                  tabIndex={0}
                                  onDoubleClick={() => startEditing(taskId, title)}
                                  onKeyDown={(e) => {
                                    if (e.key === 'Enter') startEditing(taskId, title);
                                  }}
                                  style={
                                    {
                                      cursor: 'pointer',
                                      outlineOffset: '2px',
                                    } as React.CSSProperties
                                  }
                                >
                                  {title}
                                </Text>
                              )}

                              {!isEditing ? (
                                <Button
                                  variant="outline"
                                  size="xs"
                                  aria-label={`Edit task ${title}`}
                                  onClick={() => startEditing(taskId, title)}
                                >
                                  Edit
                                </Button>
                              ) : (
                                <Stack direction="horizontal" gap={6}>
                                  <Button
                                    variant="primary"
                                    size="xs"
                                    onClick={() => void saveEditing(taskId)}
                                    loading={submitting}
                                  >
                                    Save
                                  </Button>
                                  <Button variant="ghost" size="xs" onClick={cancelEditing}>
                                    Cancel
                                  </Button>
                                </Stack>
                              )}
                            </Stack>

                            <Stack direction="horizontal" gap={8} align="center" wrap>
                              <Badge variant={getPriorityBadgeVariant(priority)} size="sm">
                                {priority}
                              </Badge>
                              <Avatar size="sm" name={assigneeName} />
                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : null}
                            </Stack>

                            <Select
                              label="Move task"
                              value={task.column || column.id}
                              onChange={(value) => void handleMoveTask(taskId, value)}
                              options={normalizedColumns.map((c) => ({ value: c.id, label: c.name }))}
                            />
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {isAddOpen && (
                    <Card shadow="none" border radius="md" padding={12}>
                      <Stack gap={8}>
                        <Input
                          label="Task title"
                          value={newTaskTitleByColumn[column.id] || ''}
                          onChange={(value) =>
                            setNewTaskTitleByColumn((prev) => ({
                              ...prev,
                              [column.id]: value,
                            }))
                          }
                          error={newTaskTitleErrorByColumn[column.id] || undefined}
                          required
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriorityByColumn[column.id] || 'medium'}
                          onChange={(value) =>
                            setNewTaskPriorityByColumn((prev) => ({
                              ...prev,
                              [column.id]: value as 'low' | 'medium' | 'high',
                            }))
                          }
                          error={newTaskPriorityErrorByColumn[column.id] || undefined}
                          required
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Stack direction="horizontal" gap={8}>
                          <Button
                            variant="primary"
                            size="sm"
                            loading={submitting}
                            disabled={
                              submitting ||
                              !(newTaskTitleByColumn[column.id] || '').trim() ||
                              !newTaskPriorityByColumn[column.id]
                            }
                            onClick={() => void handleCreateTask(column.id)}
                          >
                            Submit
                          </Button>
                          <Button variant="ghost" size="sm" onClick={() => closeAddForm(column.id)}>
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  )}

                  <Button variant="ghost" size="sm" fullWidth onClick={() => openAddForm(column.id)}>
                    Add Task
                  </Button>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  'post-transition metal': 'var(--ggui-color-neutral-500, #6b7280)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-primary-500, #0ea5e9)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-700, #0369a1)',
  lanthanide: 'var(--ggui-color-success-600, #16a34a)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

const getCategoryColor = (category?: string) =>
  categoryColorMap[(category || 'unknown').toLowerCase()] ?? 'var(--ggui-color-neutral-400, #9ca3af)';

const normalize = (value?: string) => (value || '').toLowerCase().trim();

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(
    elements.find((e) => e.atomicNumber !== undefined)?.atomicNumber
  );

  const filteredElements = useMemo(() => {
    const q = normalize(query);
    if (!q) return elements;
    return elements.filter((el) => {
      const name = normalize(el.name);
      const symbol = normalize(el.symbol);
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
