import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;

  /** Action Contract: send message callback */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount = 0,
  messages = [],
  sendMessage = () => {},
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const formatTime = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const custom = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      if (custom?.detail) {
        setStreamMessages((prev) => [...prev, custom.detail]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const onSubmit = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage(payload);
    setDraft('');
  };

  const groupedMessages = allMessages.reduce<Array<Array<{ sender?: string; text?: string; timestamp?: string }>>>(
    (groups, msg) => {
      const lastGroup = groups[groups.length - 1];
      if (!lastGroup || lastGroup[0]?.sender !== msg.sender) {
        groups.push([msg]);
      } else {
        lastGroup.push(msg);
      }
      return groups;
    },
    []
  );

  return (
    <Card
      padding={0}
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        height: '100%',
      }}
    >
      <Stack gap={0} style={{ height: '100%' }}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Badge variant="primary" size="sm">
            {participantCount}
          </Badge>
        </Stack>

        <Box
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
          ref={listRef}
          aria-label="Chat messages"
        >
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {groupedMessages.map((group, groupIndex) => {
              const sender = group[0]?.sender || 'Unknown';
              const isCurrentUser = sender === currentUser;

              return (
                <Stack key={`${sender}-${groupIndex}`} align={isCurrentUser ? 'end' : 'start'} gap={6}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {sender}
                  </Text>

                  <Stack gap={6} align={isCurrentUser ? 'end' : 'start'}>
                    {group.map((msg, msgIndex) => (
                      <Box
                        key={`${msg.timestamp || 't'}-${msgIndex}-${msg.text || ''}`}
                        style={{
                          maxWidth: '80%',
                          padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                          background: isCurrentUser
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          color: isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                          border: `1px solid ${
                            isCurrentUser
                              ? 'var(--ggui-color-primary-600, #0284c7)'
                              : 'var(--ggui-color-outline, #d4d4d8)'
                          }`,
                        }}
                      >
                        <Stack gap={4}>
                          <Text
                            variant="bodySmall"
                            color={isCurrentUser ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                          >
                            {msg.text || ''}
                          </Text>
                          <Text
                            variant="caption"
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align="right"
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                </Stack>
              );
            })}
          </Stack>
        </Box>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-2, 8px)"
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Box style={{ flex: 1 }}>
            <Input
              label=""
              aria-label="Type a message"
              placeholder="Type a message..."
              value={draft}
              onChange={setDraft}
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  onSubmit();
                }
              }}
              size="md"
            />
          </Box>
          <Button variant="primary" size="md" onClick={onSubmit} disabled={!draft.trim()} aria-label="Send message">
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string>(lastUpdated || '');
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isStreaming, setIsStreaming] = useState<boolean>(false);

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    if (lastUpdated) {
      setLiveLastUpdated(lastUpdated);
    }
  }, [lastUpdated]);

  useEffect(() => {
    const timeout = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1200);

    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        stocks?: Props['stocks'];
        lastUpdated?: string;
      }>;
      const data = customEvent.detail || {};

      if (Array.isArray(data.stocks)) {
        setLiveStocks(data.stocks);
      }
      if (typeof data.lastUpdated === 'string') {
        setLiveLastUpdated(data.lastUpdated);
      }

      setIsConnecting(false);
      setIsStreaming(true);
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);

    return () => {
      window.clearTimeout(timeout);
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      border
      radius="lg"
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          wrap
        >
          <Text
            as="div"
            size="2xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>

          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {(isConnecting || !isStreaming) && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text
              variant="bodySmall"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
              aria-live="polite"
            >
              {isConnecting
                ? 'Connecting to live feed...'
                : isStreaming
                ? `Live • Last Updated: ${formattedUpdated}`
                : `Last Updated: ${formattedUpdated}`}
            </Text>
          </Stack>
        </Stack>

        <div
          role="list"
          aria-label="Stock ticker cards"
          style={{
            display: 'grid',
            gap: 'var(--ggui-spacing-4, 16px)',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
          }}
        >
          {liveStocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;
            const trendColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const arrow = isPositive ? '▲' : '▼';

            return (
              <Card
                key={`${stock.symbol || 'stock'}-${stock.name || 'item'}-${index}`}
                padding="var(--ggui-spacing-4, 16px)"
                shadow="sm"
                border
                radius="md"
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text
                    as="div"
                    size="3xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {stock.symbol || '—'}
                  </Text>

                  <Text
                    as="div"
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    truncate
                  >
                    {stock.name || 'Unknown Company'}
                  </Text>

                  <Text
                    as="div"
                    size="xl"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {(stock.price ?? 0).toFixed(2)}
                  </Text>

                  <Stack direction="horizontal" justify="between" align="center">
                    <Text as="span" variant="label" color={trendColor}>
                      {change >= 0 ? '+' : ''}
                      {change.toFixed(2)}
                    </Text>
                    <Text as="span" variant="label" color={trendColor}>
                      {arrow} {changePercent >= 0 ? '+' : ''}
                      {changePercent.toFixed(2)}%
                    </Text>
                  </Stack>

                  <div
                    aria-hidden="true"
                    style={{
                      marginTop: 'var(--ggui-spacing-1, 4px)',
                      borderTop: `1px solid ${trendColor}`,
                    }}
                  />
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Box,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  Select,
  Stack,
  Text,
  Toggle,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action Contract: called when user completes onboarding */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? props.avatarOptions[0] ?? '');
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? props.roleOptions[0] ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });
  const [attemptedNext, setAttemptedNext] = useState<boolean>(false);

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? props.avatarOptions[0] ?? '');
    setRole(props.initialProfile?.role ?? props.roleOptions[0] ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme ?? 'light');
  }, [props.initialProfile, props.avatarOptions, props.roleOptions]);

  useEffect(() => {
    if (avatar && props.avatarOptions.length > 0 && !props.avatarOptions.includes(avatar)) {
      setAvatar(props.avatarOptions[0] ?? '');
    }
    if (!avatar && props.avatarOptions.length > 0) {
      setAvatar(props.avatarOptions[0] ?? '');
    }
  }, [avatar, props.avatarOptions]);

  useEffect(() => {
    if (role && props.roleOptions.length > 0 && !props.roleOptions.includes(role)) {
      setRole(props.roleOptions[0] ?? '');
    }
    if (!role && props.roleOptions.length > 0) {
      setRole(props.roleOptions[0] ?? '');
    }
  }, [role, props.roleOptions]);

  const emailIsValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const step1Valid = name.trim().length > 0 && emailIsValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canProceed = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;

  const roleSelectOptions = useMemo(
    () => props.roleOptions.map((optionRole) => ({ value: optionRole, label: optionRole })),
    [props.roleOptions],
  );

  const showNameError = (touched.name || attemptedNext) && name.trim().length === 0;
  const showEmailError = (touched.email || attemptedNext) && (!email || !emailIsValid);

  const handleBack = () => setCurrentStep((prev) => (prev > 1 ? ((prev - 1) as 1 | 2 | 3) : 1));
  const handleNext = () => {
    setAttemptedNext(true);
    if (!canProceed) return;
    setAttemptedNext(false);
    setCurrentStep((prev) => (prev < 3 ? ((prev + 1) as 1 | 2 | 3) : 3));
  };

  const handleComplete = () => {
    props.onComplete?.({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Box
      padding="var(--ggui-spacing-6, 24px)"
      background="var(--ggui-color-surface, #fafafa)"
      borderRadius="var(--ggui-shape-radius-lg, 12px)"
    >
      <MotionKeyframes />
      <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
        <Card padding={24} radius="lg" shadow="md" border>
          <Stack gap={20}>
            <Stack gap={8}>
              <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                Onboarding
              </Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {currentStep} of 3
              </Text>
              <Progress size="md" variant="default" value={(currentStep / 3) * 100} />
            </Stack>

            <Divider color="var(--ggui-color-outline, #d4d4d8)" />

            <Box
              padding="var(--ggui-spacing-4, 16px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                animation: motionEnabled ? 'ggui-slideInUp 200ms ease-out' : 'none',
              }}
            >
              {currentStep === 1 && (
                <Stack gap={16}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Profile Setup
                  </Text>

                  <Input
                    size="md"
                    label="Name"
                    required
                    value={name}
                    onChange={(value) => {
                      setName(value);
                      if (!touched.name) setTouched((prev) => ({ ...prev, name: true }));
                    }}
                    error={showNameError ? 'Name is required' : undefined}
                    placeholder="Enter your name"
                  />

                  <Input
                    size="md"
                    type="email"
                    label="Email"
                    required
                    value={email}
                    onChange={(value) => {
                      setEmail(value);
                      if (!touched.email) setTouched((prev) => ({ ...prev, email: true }));
                    }}
                    error={showEmailError ? 'Please enter a valid email address' : undefined}
                    placeholder="Enter your email"
                  />

                  <Stack gap={8}>
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                      Avatar Selection
                    </Text>
                    <Box role="group" aria-label="Avatar options">
                      <Stack direction="horizontal" gap={8} wrap align="start">
                        {props.avatarOptions.map((emoji) => {
                          const selected = emoji === avatar;
                          return (
                            <Button
                              key={emoji}
                              variant={selected ? 'primary' : 'outline'}
                              size="md"
                              aria-pressed={selected}
                              aria-label={`Select avatar ${emoji}`}
                              onClick={() => setAvatar(emoji)}
                              style={
                                selected
                                  ? {
                                      background: 'var(--ggui-color-container, #ede9fe)',
                                      color: 'var(--ggui-color-onContainer, #4c1d95)',
                                      borderColor: 'var(--ggui-color-primary-600, #0284c7)',
                                    }
                                  : undefined
                              }
                            >
                              {emoji}
                            </Button>
                          );
                        })}
                      </Stack>
                    </Box>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Choose the avatar that best represents you.
                    </Text>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={16}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Text>

                  <Select
                    size="md"
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={roleSelectOptions}
                    placeholder="Select your role"
                    required
                    error={attemptedNext && role.trim().length === 0 ? 'Role is required' : undefined}
                  />

                  <Toggle
                    size="md"
                    label={`Email Notifications: ${emailNotifications ? 'On' : 'Off'}`}
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />

                  <Toggle
                    size="md"
                    label={`Theme Preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={16}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Review &amp; Confirm
                  </Text>

                  <Stack gap={8}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Name: {name}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Email: {email}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Avatar: {avatar}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Role: {role}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Email Notifications: {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      Theme: {theme === 'dark' ? 'Dark' : 'Light'}
                    </Text>
                  </Stack>

                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Use Go Back to edit any details before completing setup.
                  </Text>
                </Stack>
              )}
            </Box>

            <Divider color="var(--ggui-color-outline, #d4d4d8)" />

            <Stack direction="horizontal" justify="between" align="center" gap={8} wrap>
              <Button
                variant="ghost"
                size="md"
                onClick={handleBack}
                disabled={currentStep === 1}
                fullWidth={currentStep === 1}
              >
                {currentStep === 3 ? 'Go Back' : 'Back'}
              </Button>

              {currentStep < 3 ? (
                <Button variant="primary" size="md" onClick={handleNext} disabled={!canProceed} fullWidth>
                  Next
                </Button>
              ) : (
                <Button variant="primary" size="md" onClick={handleComplete} fullWidth>
                  Complete Setup
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Container>
    </Box>
  );
}

