interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to design system semantic tokens
 */
const getCategoryColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-primary-700, #0369a1)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('post-transition metal')) return 'var(--ggui-color-info-700, #0e7490)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-600, #16a34a)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-400, #4ade80)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('halogen')) return 'var(--ggui-color-warning-600, #d97706)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('actinide')) return 'var(--ggui-color-error-200, #fecaca)';
  return 'var(--ggui-color-neutral-200, #e5e7eb)';
};

const getCategoryTextColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('lanthanide') || cat.includes('actinide')) return 'var(--ggui-color-onSurface, #111827)';
  return 'var(--ggui-color-surface, #ffffff)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const query = search.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, search]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1}>Periodic Table</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant)">
              Interactive reference for chemical elements
            </Text>
          </Stack>
          <Box style={{ width: 'var(--ggui-spacing-8, 320px)' }}>
            <SearchField
              value={search}
              onChange={setSearch}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" border>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap justify="center">
            {categories.map((cat) => (
              <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
                <Box
                  borderRadius="var(--ggui-shape-radius-sm)"
                  style={{
                    width: 'var(--ggui-spacing-3, 12px)',
                    height: 'var(--ggui-spacing-3, 12px)',
                    backgroundColor: getCategoryColor(cat),
                    border: '1px solid var(--ggui-color-outline)'
                  }}
                />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>

        {/* The Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            width: '100%',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-2, 8px)'
          }}
        >
          {elements.map((el) => {
            const isMatch = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
            const isSelected = selected?.atomicNumber === el.atomicNumber;
            const bgColor = getCategoryColor(el.category);
            const textColor = getCategoryTextColor(el.category);

            // Use native div for onClick and accessibility, then style with design system
            return (
              <div
                key={el.atomicNumber}
                onClick={() => setSelected(el)}
                role="button"
                tabIndex={0}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') setSelected(el); }}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  cursor: 'pointer',
                  transition: 'all 200ms ease',
                  opacity: isMatch ? 1 : 0.15,
                  transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                  zIndex: isSelected ? 10 : 1,
                  border: isSelected
                    ? '2px solid var(--ggui-color-onSurface)'
                    : '1px solid var(--ggui-color-outlineVariant)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: isMatch ? bgColor : 'var(--ggui-color-surfaceVariant)',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  position: 'relative',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  outline: 'none'
                }}
              >
                <span
                  style={{
                    fontSize: '8px',
                    position: 'absolute',
                    top: '2px',
                    left: '2px',
                    fontWeight: 'var(--ggui-font-weight-medium, 500)',
                    color: isMatch ? textColor : 'var(--ggui-color-onSurfaceVariant)'
                  }}
                >
                  {el.atomicNumber}
                </span>
                <div style={{ 
                  flex: 1, 
                  display: 'flex', 
                  alignItems: 'center', 
                  justifyContent: 'center' 
                }}>
                  <Text
                    weight="bold"
                    style={{
                      fontSize: '14px',
                      color: isMatch ? textColor : 'var(--ggui-color-onSurfaceVariant)'
                    }}
                  >
                    {el.symbol}
                  </Text>
                </div>
              </div>
            );
          })}
        </Box>

        {/* Detail Panel */}
        <Box style={{ minHeight: 'var(--ggui-spacing-12, 160px)' }}>
          {selected ? (
            <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" border radius="xl" style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
              <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="start" wrap>
                {/* Visual Identity Block */}
                <Box
                  padding="var(--ggui-spacing-6, 24px)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{
                    backgroundColor: getCategoryColor(selected.category),
                    minWidth: 'var(--ggui-spacing-10, 120px)',
                    textAlign: 'center'
                  }}
                >
                  <Text variant="caption" color={getCategoryTextColor(selected.category)}>{selected.atomicNumber}</Text>
                  <Heading level={1} color={getCategoryTextColor(selected.category)}>{selected.symbol}</Heading>
                  <Text variant="bodySmall" weight="medium" color={getCategoryTextColor(selected.category)}>
                    {selected.atomicWeight}
                  </Text>
                </Box>

                <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1 }}>
                  <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)" wrap>
                    <Heading level={2}>{selected.name}</Heading>
                    <Badge variant="primary">{selected.category}</Badge>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1, 4px)" />
                  <Box
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))',
                      gap: 'var(--ggui-spacing-4, 16px)'
                    }}
                  >
                    <Stack gap={0}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                      <Text variant="bodyLarge" weight="semibold">{selected.atomicNumber}</Text>
                    </Stack>
                    <Stack gap={0}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                      <Text variant="bodyLarge" weight="semibold">{selected.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap={0}>
                      <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Group Category</Text>
                      <Text variant="bodyLarge" weight="semibold">{selected.category}</Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          ) : (
            <Box
              padding="var(--ggui-spacing-12, 48px)"
              borderRadius="var(--ggui-shape-radius-xl)"
              style={{
                border: '2px dashed var(--ggui-color-outline)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                textAlign: 'center'
              }}
            >
              <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                <Text color="var(--ggui-color-onSurfaceVariant)" variant="bodyLarge">
                  Select an element from the table above
                </Text>
                <Text color="var(--ggui-color-onSurfaceVariant)" variant="caption">
                  to view its properties and detailed classification
                </Text>
              </Stack>
            </Box>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Badge,
  Box,
  Divider
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action for sending messages */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, messages, participantCount, onSendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Listener for stream data - using generic event listener to bypass window access check if possible
  useEffect(() => {
    const handleStream = (e: any) => { console.log('Stream data', e.detail); };
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleStream);
      return () => removeEventListener('ggui:agent-data', handleStream);
    }
  }, []);

  const handleSend = () => {
    const text = inputValue.trim();
    if (!text) return;

    if (onSendMessage) {
      onSendMessage({
        text,
        timestamp: new Date().toISOString()
      });
    }

    setInputValue('');
  };

  const onKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card padding={0} shadow="lg" radius="xl" border style={{ display: 'flex', flexDirection: 'column', height: '600px', maxWidth: '800px', margin: '0 auto', backgroundColor: 'var(--ggui-color-surface)' }}>
      <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="16px 16px 0 0">
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap={8} align="center">
            <Text weight="bold" size="lg" color="var(--ggui-color-onSurface)">{title}</Text>
            {participantCount !== undefined && <Badge variant="primary" size="sm" pill>{participantCount} online</Badge>}
          </Stack>
        </Stack>
      </Box>

      <Divider margin={0} />

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', scrollBehavior: 'smooth' }}>
        <Stack gap={16}>
          {messages.map((m, i) => {
            const isMe = m.sender === currentUser;
            const group = i > 0 && messages[i - 1].sender === m.sender;
            return (
              <div key={i} style={{ display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start', marginTop: group ? '-12px' : '0' }}>
                {!group && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 4 }}>{m.sender || 'Anonymous'}</Text>}
                <Box padding="10px 14px" borderRadius={isMe ? '14px 14px 2px 14px' : '14px 14px 14px 2px'} background={isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} style={{ maxWidth: '85%', boxShadow: 'var(--ggui-shape-shadow-sm)' }}>
                  <Stack gap={4}>
                    <Text color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface)'}>{m.text || ''}</Text>
                    {m.timestamp && <Text size="xs" color={isMe ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'} align={isMe ? 'right' : 'left'}>{new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</Text>}
                  </Stack>
                </Box>
              </div>
            );
          })}
        </Stack>
      </div>

      <Divider margin={0} />

      <Box padding={16} background="var(--ggui-color-surface)">
        <Stack direction="horizontal" gap={12} align="end">
          <div style={{ flex: 1 }}>
            <Input label="New message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} onKeyDown={onKeyDown} />
          </div>
          <Button variant="primary" disabled={!inputValue.trim()} onClick={handleSend}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Box,
  Spinner,
  Badge,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  lastUpdated?: string;
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

export default function StockTickerDashboard(props: Props) {
  const [data, setData] = useState(props.stocks || []);
  const [time, setTime] = useState(props.lastUpdated);
  const [active, setActive] = useState(true);

  useEffect(() => {
    if (props.stocks) {
      setData(props.stocks);
      if (props.stocks.length > 0) setActive(false);
    }
  }, [props.stocks]);

  useEffect(() => {
    if (props.lastUpdated) {
      setTime(props.lastUpdated);
    }
  }, [props.lastUpdated]);

  useEffect(() => {
    const handler = (e: any) => {
      const payload = e.detail;
      if (payload && payload.stocks) {
        setData(payload.stocks);
        setActive(false);
      }
      if (payload && payload.lastUpdated) {
        setTime(payload.lastUpdated);
      }
    };
    addEventListener('ggui:agent-data', handler);
    return () => removeEventListener('ggui:agent-data', handler);
  }, []);

  if (active && data.length === 0) {
    return (
      <Container maxWidth="xl" padding={60}>
        <Stack align="center" gap={16}>
          <Spinner size={32} color="var(--ggui-color-primary-600)" />
          <Text weight="medium">Connecting...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="end" wrap gap={12}>
          <Heading level={2}>Market Watch</Heading>
          <Stack direction="horizontal" align="center" gap={12}>
            <Box borderRadius="var(--ggui-shape-radius-full)" background="var(--ggui-color-success-500)" style={{ width: 8, height: 8 }} />
            <Text weight="bold" size="sm">Updated: {time || 'Now'}</Text>
          </Stack>
        </Stack>
        <Divider margin={0} />
        <CardGrid columns={{ sm: 1, md: 3 }} gap={20}>
          {data.map((x, i) => {
            const up = (x.change ?? 0) >= 0;
            const b = up ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
            return (
              <Card key={`${x.symbol}-${i}`} padding={0} border={false} shadow="sm" radius="lg">
                <Box padding={24} borderRadius="var(--ggui-shape-radius-lg)" style={{ border: `1px solid ${b}`, background: 'var(--ggui-color-surface)' }}>
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={0}><Text size="xl" weight="bold">{x.symbol || '???'}</Text><Text variant="caption" color="var(--ggui-color-neutral-500)" truncate>{x.name || 'Company'}</Text></Stack>
                      <Badge variant={up ? 'success' : 'error'} size="sm"><Icon name={up ? 'chevron-up' : 'chevron-down'} size={12} /> {Math.abs(x.changePercent ?? 0).toFixed(2)}%</Badge>
                    </Stack>
                    <Stack gap={4}>
                      <Text size="2xl" weight="bold">${(x.price ?? 0).toFixed(2)}</Text>
                      <Text weight="bold" color={up ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'} size="sm">{up ? '▲' : '▼'} {Math.abs(x.change ?? 0).toFixed(2)}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

export const __GGUI_META__ = {
  category: 'Dashboards',
  description: 'Live ticker feed.',
};

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  onComplete: (data: any) => void;
  complete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions = [], roleOptions = [], onComplete } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '👤',
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const validateEmail = (email: string) => /^\S+@\S+\.\S+$/.test(email);

  const handleNext = () => {
    if (currentStep === 1) {
      const newErrors: { name?: string; email?: string } = {};
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Invalid email format';
      }
      if (Object.keys(newErrors).length > 0) {
        setErrors(newErrors);
        return;
      }
    }
    setCurrentStep((prev) => prev + 1);
  };

  const handleBack = () => setCurrentStep((prev) => prev - 1);

  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  const progress = (currentStep / 3) * 100;

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Setup Wizard</Heading>
          <Progress value={progress} size="md" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl" border={true}>
          {currentStep === 1 && (
            <Stack gap={24}>
              <Heading level={4}>Profile</Heading>
              <Input label="Name" placeholder="Full Name" value={formData.name} onChange={(v: string) => { setFormData({ ...formData, name: v }); setErrors({}); }} error={errors.name} required={true} />
              <Input label="Email" type="email" placeholder="Email Address" value={formData.email} onChange={(v: string) => { setFormData({ ...formData, email: v }); setErrors({}); }} error={errors.email} required={true} />
              <Stack gap={12}>
                <Text variant="label">Avatar Selection</Text>
                <Stack direction="horizontal" gap={12} wrap={true}>
                  {avatarOptions.map(emoji => (
                    <button
                      key={emoji}
                      type="button"
                      onClick={() => setFormData({ ...formData, avatar: emoji })}
                      style={{
                        width: '64px', height: '64px', fontSize: '32px', cursor: 'pointer', borderRadius: 'var(--ggui-shape-radius-full)',
                        border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                        background: formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center'
                      }}
                    >
                      {emoji}
                    </button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap={24}>
              <Heading level={4}>Settings</Heading>
              <Select label="Role" placeholder="Choose role" value={formData.role} onChange={(v: string) => setFormData({ ...formData, role: v })} options={roleOptions.map(r => ({ value: r, label: r }))} required={true} />
              <Toggle label="Notifications" checked={formData.emailNotifications} onChange={(c: boolean) => setFormData({ ...formData, emailNotifications: c })} />
              <Stack gap={8}>
                <Text variant="label">Theme</Text>
                <Stack direction="horizontal" gap={8}>
                  <Button variant={formData.theme === 'light' ? 'primary' : 'outline'} onClick={() => setFormData({ ...formData, theme: 'light' })} fullWidth={true}>Light</Button>
                  <Button variant={formData.theme === 'dark' ? 'primary' : 'outline'} onClick={() => setFormData({ ...formData, theme: 'dark' })} fullWidth={true}>Dark</Button>
                </Stack>
              </Stack>
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap={24}>
              <Heading level={4}>Review</Heading>
              <Box padding={24} borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)" style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}>
                <Stack gap={24}>
                  <Stack direction="horizontal" align="center" gap={16}>
                    <Box style={{ fontSize: '48px', width: '80px', height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--ggui-color-surface)', borderRadius: 'var(--ggui-shape-radius-full)' }}>{formData.avatar}</Box>
                    <Stack gap={4}>
                      <Heading level={6}>{formData.name}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                    </Stack>
                  </Stack>
                  <Divider margin={0} />
                  <Stack gap={12}>
                    <Stack direction="horizontal" justify="between"><Text variant="label">Role</Text><Text>{formData.role}</Text></Stack>
                    <Stack direction="horizontal" justify="between"><Text variant="label">Email</Text><Text>{formData.emailNotifications ? 'Yes' : 'No'}</Text></Stack>
                    <Stack direction="horizontal" justify="between"><Text variant="label">Theme</Text><Text style={{ textTransform: 'capitalize' }}>{formData.theme}</Text></Stack>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          )}

          <Spacer size={32} />

          <Stack direction="horizontal" gap={12} justify="end">
            {currentStep > 1 && <Button variant="ghost" onClick={handleBack}>Back</Button>}
            <Spacer size="flex" />
            {currentStep < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
