}: Props) {
  // Helper to map condition names to common weather emojis
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('clear')) return '✨';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '🌡️';
  };

  return (
    <Card padding={24} shadow="md" radius="xl" border={true}>
      <Stack gap={24}>
        {/* Header Section: City and Main Temp */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #111827)">
              {city}
            </Heading>
            <Stack direction="horizontal" gap={8} align="center">
              <Text size="xl">{getConditionEmoji(condition)}</Text>
              <Text
                variant="bodyLarge"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {condition}
              </Text>
            </Stack>
          </Stack>
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}°{unit}
          </Text>
        </Stack>

        {/* Current Details Section */}
        <Stack direction="horizontal" gap={32} align="center">
          <Stack gap={4}>
            <Text
              variant="overline"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              HUMIDITY
            </Text>
            <Text size="lg" weight="semibold">
              {humidity}%
            </Text>
          </Stack>
          <Stack gap={4}>
            <Text
              variant="overline"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              WIND SPEED
            </Text>
            <Text size="lg" weight="semibold">
              {windSpeed} mph
            </Text>
          </Stack>
        </Stack>

        {/* Forecast Separator */}
        <Divider
          margin={0}
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        {/* 5-Day Forecast Grid */}
        <Box>
          <Stack direction="horizontal" justify="between" align="center">
            {forecast.slice(0, 5).map((item, index) => (
              <Stack
                key={`forecast-${item.day}-${index}`}
                gap={8}
                align="center"
                style={{ flex: 1 }}
              >
                <Text
                  variant="caption"
                  weight="medium"
                  color="var(--ggui-color-neutral-500, #6b7280)"
                >
                  {item.day}
                </Text>
                <Text size="lg" style={{ lineHeight: 1 }}>
                  {item.icon}
                </Text>
                <Stack gap={2} align="center">
                  <Text weight="semibold" size="sm">
                    {item.high}°
                  </Text>
                  <Text
                    size="xs"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                  >
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Stack, 
  Box, 
  Text, 
  Card, 
  Badge, 
  Heading, 
  Divider
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

type BadgeVariant = 'error' | 'warning' | 'primary' | 'success' | 'info' | 'default' | 'secondary';

/**
 * Maps element categories to semantic design tokens.
 */
const getCategoryColor = (category?: string) => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-200, #a5f3fc)';
  if (cat.includes('halogen')) return 'var(--ggui-color-warning-200, #fde68a)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-info-100, #cffafe)';
  return 'var(--ggui-color-neutral-50, #f9fafb)';
};

/**
 * Maps categories to Badge variants for the legend and details.
 */
const getBadgeVariant = (category?: string): BadgeVariant => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'error';
  if (cat.includes('alkaline earth')) return 'warning';
  if (cat.includes('transition metal')) return 'primary';
  if (cat.includes('metalloid')) return 'success';
  if (cat.includes('noble gas') || cat.includes('nonmetal')) return 'info';
  return 'default';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Extract unique categories for the legend
  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach(el => {
      if (el.category) set.add(el.category);
    });
    return Array.from(set).sort();
  }, [elements]);

  const handleElementClick = (el: ElementData) => {
    setSelectedElement(el);
  };

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header and Search */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive element explorer
            </Text>
          </Stack>
          <Box style={{ minWidth: 'var(--ggui-spacing-72, 288px)' }}>
            <SearchField 
              placeholder="Filter by name or symbol..." 
              value={searchQuery}
              onChange={setSearchQuery}
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Box 
          padding="var(--ggui-spacing-2, 8px)" 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap justify="center">
            {categories.map(cat => (
              <Badge key={cat} variant={getBadgeVariant(cat)} size="sm">
                {cat}
              </Badge>
            ))}
          </Stack>
        </Box>

        {/* Periodic Table Grid Container */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-12, 48px), 1fr))',
              gridAutoRows: 'minmax(var(--ggui-spacing-16, 64px), auto)',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: 'calc(18 * var(--ggui-spacing-12, 48px))'
            }}
          >
            {elements.map((el) => {
              const nameLower = el.name?.toLowerCase() || '';
              const symbolLower = el.symbol?.toLowerCase() || '';
              const searchLower = searchQuery.toLowerCase();
              const isMatch = !searchQuery || nameLower.includes(searchLower) || symbolLower.includes(searchLower);

              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

              return (
                <div
                  key={el.atomicNumber}
                  onClick={() => handleElementClick(el)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      handleElementClick(el);
                    }
                  }}
                  role="button"
                  tabIndex={0}
                  aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    backgroundColor: getCategoryColor(el.category),
                    padding: 'var(--ggui-spacing-1, 4px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    border: isSelected 
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                      : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                    position: 'relative',
                    transition: 'transform 100ms ease, box-shadow 100ms ease, opacity 100ms ease',
                    opacity: isMatch ? 1 : 0.25,
                    filter: isMatch ? 'none' : 'grayscale(0.8)',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none',
                    transform: isSelected ? 'scale(1.05)' : 'none',
                    zIndex: isSelected ? 10 : 1,
                    outline: 'none'
                  }}
                >
                  <Text 
                    variant="caption" 
                    style={{ 
                      position: 'absolute', 
                      top: 'var(--ggui-spacing-0-5, 2px)', 
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      transform: 'scale(0.8)',
                      transformOrigin: 'top left',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)'
                    }}
                  >
                    {el.atomicNumber}
                  </Text>
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {el.symbol}
                  </Text>
                  <Text 
                    variant="caption" 
                    truncate 
                    style={{ 
                      fontSize: 'var(--ggui-font-size-xs, 12px)', 
                      transform: 'scale(0.7)',
                      transformOrigin: 'top center',
                      marginTop: 'var(--ggui-spacing-0-5, 2px)', 
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)' 
                    }}
                  >
                    {el.name}
                  </Text>
                </div>
              );
            })}
          </div>
        </Box>

        {/* Detail Panel */}
        {selectedElement ? (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" border radius="xl">
            <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="center" wrap>
              <Box 
                padding="var(--ggui-spacing-6, 24px)" 
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                background={getCategoryColor(selectedElement.category)}
                style={{ 
                  minWidth: 'var(--ggui-spacing-32, 128px)', 
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                }}
              >
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {selectedElement.atomicNumber}
                </Text>
                <Heading level={1} style={{ margin: 'var(--ggui-spacing-2, 8px) 0' }}>
                  {selectedElement.symbol}
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {selectedElement.atomicWeight}
                </Text>
              </Box>

              <Stack gap="var(--ggui-spacing-3, 12px)" style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Heading level={3}>{selectedElement.name}</Heading>
                  <Box>
                    <Badge variant={getBadgeVariant(selectedElement.category)}>
                      {selectedElement.category}
                    </Badge>
                  </Box>
                </Stack>

                <Divider margin="var(--ggui-spacing-2, 8px)" />

                <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" wrap>
                  <Stack gap="var(--ggui-spacing-0-5, 2px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">{selectedElement.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-0-5, 2px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Position</Text>
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">Row {selectedElement.row}, Column {selectedElement.col}</Text>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        ) : (
          <Box 
            padding="var(--ggui-spacing-6, 24px)" 
            borderRadius="var(--ggui-shape-radius-lg, 12px)" 
            style={{ 
              border: '2px dashed var(--ggui-color-outline, #d4d4d8)',
              textAlign: 'center'
            }}
          >
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view detailed properties.
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Box,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Badge,
  Divider
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  sendMessage: (payload: { text: string; timestamp: string }) => void;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages, sendMessage, onSendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  useEffect(() => {
    const handler = (e: any) => console.log('Data:', e.detail);
    addEventListener('ggui:agent-data', handler);
    return () => removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = () => {
    const text = inputValue.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage(payload);
    if (onSendMessage) onSendMessage(payload);
    setInputValue('');
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="lg" 
      border
      style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        height: '600px', 
        maxWidth: '800px', 
        margin: '0 auto',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)'
      }}
    >
      <Box padding="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Heading level={4}>{title}</Heading>
            {participantCount !== undefined && <Badge variant="primary" size="sm" pill>{participantCount} online</Badge>}
          </Stack>
        </Stack>
      </Box>
      <Divider margin={0} />

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column' }}>
        <Stack gap="var(--ggui-spacing-4, 16px)">
          {messages.map((msg, idx) => {
            const isMe = msg.sender === currentUser;
            const isConsecutive = idx > 0 && messages[idx - 1].sender === msg.sender;
            return (
              <Stack key={`${msg.timestamp}-${idx}`} align={isMe ? 'end' : 'start'} gap="var(--ggui-spacing-1, 4px)" style={{ maxWidth: '85%', alignSelf: isMe ? 'flex-end' : 'flex-start', marginTop: isConsecutive ? 'calc(var(--ggui-spacing-2, 8px) * -1)' : '0' }}>
                {!isMe && !isConsecutive && <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #71717a)">{msg.sender}</Text>}
                <Box paddingX="var(--ggui-spacing-4, 16px)" paddingY="var(--ggui-spacing-2, 8px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surface, #ffffff)'} style={{ borderBottomRightRadius: isMe ? '4px' : 'var(--ggui-shape-radius-lg, 12px)', borderBottomLeftRadius: isMe ? 'var(--ggui-shape-radius-lg, 12px)' : '4px', boxShadow: isMe ? 'none' : 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' }}>
                  <Text variant="bodySmall" color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>{msg.text}</Text>
                </Box>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant, #a1a1aa)">{formatTime(msg.timestamp)}</Text>
              </Stack>
            );
          })}
        </Stack>
      </div>

      <Divider margin={0} />

      <Box padding="var(--ggui-spacing-4, 16px)">
        {/* @ts-ignore */}
        <Text as="label" htmlFor="chat-input-area" label="Write message" variant="label">Message</Text>
        <Input id="chat-input-area" label="Message" placeholder="Type message..." value={inputValue} onChange={setInputValue} onKeyDown={(e: any) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }} />
        <Button variant="primary" disabled={!inputValue.trim()} onClick={() => handleSend()} size="md" style={{ marginTop: '8px' }}>Send</Button>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockData[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays a grid of stock prices with color-coded performance cards.
 * Responds to agent data updates via props or stream events.
 */
export default function StockDashboard(props: Props) {
  const { stocks = [], lastUpdated } = props;
  const [isConnecting, setIsConnecting] = useState(stocks.length === 0);

  // Sync loading state with data availability
  useEffect(() => {
    if (stocks.length > 0) {
      setIsConnecting(false);
    }
  }, [stocks]);

  const formatCurrency = (val?: number) => {
    if (val === undefined) return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
    }).format(val);
  };

  const formatPercent = (val?: number) => {
    if (val === undefined) return '0.00%';
    const sign = val >= 0 ? '+' : '';
    return `${sign}${val.toFixed(2)}%`;
  };

  const formatChange = (val?: number) => {
    if (val === undefined) return '0.00';
    const sign = val >= 0 ? '+' : '';
    return `${sign}${val.toFixed(2)}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return 'Awaiting update...';
    try {
      const date = new Date(dateStr);
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch (e) {
      return dateStr;
    }
  };

  // Loading / Connecting State
  if (isConnecting) {
    return (
      <Container padding="var(--ggui-spacing-12, 48px)">
        <Stack align="center" justify="center" gap="var(--ggui-spacing-4, 16px)">
          <Spinner size={40} color="var(--ggui-color-primary-600)" />
          <Stack align="center" gap="var(--ggui-spacing-1, 4px)">
            <Text weight="medium">Connecting to Market Stream</Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Initializing real-time equity data...
            </Text>
          </Stack>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" align="center" justify="between" wrap gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live performance of tracked symbols
            </Text>
          </Stack>

          <Box
            paddingX="var(--ggui-spacing-3, 12px)"
            paddingY="var(--ggui-spacing-2, 8px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
            style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}
          >
            <Box 
              borderRadius="var(--ggui-shape-radius-full, 9999px)" 
              background="var(--ggui-color-success-500, #22c55e)" 
              style={{ width: '8px', height: '8px' }} 
            />
            <Text variant="caption" weight="semibold">
              LIVE: {formatDate(lastUpdated)}
            </Text>
          </Box>
        </Stack>

        {/* Responsive Card Grid (1 col mobile, 3 col desktop) */}
        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={24}>
          {stocks.map((stock) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const statusColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const statusBg = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';
            const statusBorder = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-6, 24px)"
                shadow="sm"
                radius="xl"
                border={true}
                style={{
                  borderColor: statusBorder,
                  transition: 'all 200ms ease-out',
                  height: '100%',
                  borderWidth: '2px'
                }}
              >
                <Stack gap="var(--ggui-spacing-6, 24px)" justify="between" style={{ height: '100%' }}>
                  {/* Symbol Header */}
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text size="2xl" weight="bold" style={{ letterSpacing: 'var(--ggui-font-letterSpacing-tight, -0.025em)' }}>
                        {stock.symbol}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                        {stock.name}
                      </Text>
                    </Stack>
                    <Icon
                      name={isPositive ? 'chevron-up' : 'chevron-down'}
                      size={24}
                      color={statusColor}
                    />
                  </Stack>

                  {/* Pricing Data */}
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text size="3xl" weight="bold">
                      {formatCurrency(stock.price)}
                    </Text>

                    <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="center">
                      <Text variant="label" weight="semibold" color={statusColor}>
                        {formatChange(stock.change)}
                      </Text>

                      <Box
                        paddingX="var(--ggui-spacing-2, 8px)"
                        paddingY="var(--ggui-spacing-1, 4px)"
                        background={statusBg}
                        borderRadius="var(--ggui-shape-radius-md, 8px)"
                        style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        <Text size="xs" weight="bold" color={statusColor}>
                          {formatPercent(stock.changePercent)}
                        </Text>
                        <Text size="xs" color={statusColor} style={{ lineHeight: 1 }}>
                          {isPositive ? '▲' : '▼'}
                        </Text>
                      </Box>
                    </Stack>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Card, Text, Heading, Input, Select, Toggle, Button, Progress, Box, Spacer, Divider, Container } from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile = {} } = props;
  const complete = (props as any).complete;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile.role || (roleOptions && roleOptions[0]) || '',
    emailNotifications: initialProfile.emailNotifications !== false,
    theme: initialProfile.theme || 'light',
  });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = useMemo(() => formData.name.trim().length > 0 && isValidEmail(formData.email), [formData.name, formData.email]);

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="lg" padding={32} radius="xl">
        <Stack gap={24}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>Onboarding</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} variant="default" size="sm" />
          </Stack>

          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap={20}>
                <Heading level={4}>Profile Setup</Heading>
                <Stack gap={4}>
                  <Text as="label" variant="label">Name</Text>
                  <Input label="Name" placeholder="Full name" value={formData.name} onChange={(v) => setFormData(p => ({ ...p, name: v }))} required />
                </Stack>
                <Stack gap={4}>
                  <Text as="label" variant="label">Email</Text>
                  <Input label="Email" type="email" placeholder="email@example.com" value={formData.email} onChange={(v) => setFormData(p => ({ ...p, email: v }))} error={formData.email && !isValidEmail(formData.email) ? 'Invalid' : ''} required />
                </Stack>
                <Stack gap={8}>
                  <Text variant="label">Avatar Selection</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map(emoji => (
                      <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} onClick={() => setFormData(p => ({ ...p, avatar: emoji }))} style={{ fontSize: '24px', width: '56px', height: '56px', padding: 0 }}>{emoji}</Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Preferences</Heading>
                <Select label="Role Selection" value={formData.role} onChange={v => setFormData(p => ({ ...p, role: v }))} options={roleOptions.map(r => ({ label: r, value: r }))} />
                <Stack gap={16}>
                  <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={v => setFormData(p => ({ ...p, emailNotifications: v }))} />
                  <Divider margin={8} />
                  <Stack direction="horizontal" align="center" justify="between">
                    <Text variant="label">Theme Mode</Text>
                    <Stack direction="horizontal" gap={12} align="center">
                      <Text variant="bodySmall">Light</Text>
                      <Toggle checked={formData.theme === 'dark'} onChange={v => setFormData(p => ({ ...p, theme: v ? 'dark' : 'light' }))} />
                      <Text variant="bodySmall">Dark</Text>
                    </Stack>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Review & Confirm</Heading>
                <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={12} style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}>
                  <Stack gap={16}>
                    <Text variant="bodyLarge" weight="semibold">{formData.name}</Text>
                    <Text variant="bodySmall">{formData.email}</Text>
                    <Divider margin={4} />
                    <SummaryRow label="Role" value={formData.role} />
                    <SummaryRow label="Theme" value={formData.theme} />
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between" align="center">
            <Box>{step > 1 && <Button variant="ghost" onClick={() => setStep(step - 1)}>Go Back</Button>}</Box>
            <Button variant="primary" onClick={() => step === 3 ? (complete && complete(formData)) : setStep(step + 1)} disabled={step === 1 && !isStep1Valid}>{step === 3 ? 'Complete Setup' : 'Continue'}</Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

function SummaryRow({ label, value }: { label: string; value: string }) {
  return (
    <Stack direction="horizontal" justify="between">
      <Text variant="label">{label}</Text>
      <Text weight="medium">{value}</Text>
    </Stack>
  );
}
